/// Per-block §5.11.34 `residual()` quantiser / tx-type context — the
/// fields the §5.11.47 `transform_type` reader, §5.11.40
/// `compute_tx_type` derivation, and §7.12.3 step-1 dequant loop need
/// beyond what the §5.11.34 dispatcher already plumbs.
///
/// Constructed once per block (the §5.11.5 walker derives every field
/// from the per-block syntax it already parses) and forwarded to
/// [`PartitionWalker::residual`].
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct ResidualContext {
    /// §5.9.18 / §7.12.2 per-frame quantiser state. Drives
    /// `get_dc_quant` / `get_ac_quant`.
    pub quant: QuantizerParams,
    /// §5.11.4 `reduced_tx_set` — the frame-header bit gating the
    /// §5.11.48 `get_tx_set()` reduction.
    pub reduced_tx_set: bool,
    /// §8.3.2 `intra_tx_type` `intraDir` — the [`intra_dir`] result for
    /// the current block. Unused on the inter path (the §8.3.2
    /// `inter_tx_type` CDF has no `intraDir` axis).
    pub intra_dir: usize,
    /// `segment_id` per §5.11.9 / §5.9.14. Drives `get_qindex` and
    /// `SegQMLevel[plane][segment_id]`.
    pub segment_id: u8,
    /// `SegQMLevel[ plane ][ segment_id ]` per §6.8.13. Three planes,
    /// `15` for the "skip QM" sentinel. Stored as a flat `[u8; 3]` —
    /// indexed by `plane`. Pass `[15; 3]` to force the no-QM identity
    /// path (matches the `using_qmatrix == false` path of the §7.12.3
    /// step-1 loop).
    pub seg_qm_level: [u8; 3],
    /// `UVMode` per §5.11.7 / §5.11.22 — the chroma intra-prediction
    /// mode. Drives `compute_tx_type`'s `Mode_To_Txfm[UVMode]` lookup
    /// on the chroma path. `DC_PRED = 0` for the walker's intra-only
    /// path until the §5.11.7 reader's chroma arm lands.
    pub uv_mode: u8,
}

impl ResidualContext {
    /// Neutral / DC-only `ResidualContext` — `base_q_idx` configurable,
    /// every other slot at its spec default (no QM, no segmentation,
    /// `UVMode = DC_PRED`). Useful for the §5.11.5 walker's reachable
    /// path and for tests.
    #[must_use]
    pub const fn neutral(base_q_idx: u8, bit_depth: u8) -> Self {
        Self {
            quant: QuantizerParams::neutral(base_q_idx, bit_depth),
            reduced_tx_set: false,
            intra_dir: 0,
            segment_id: 0,
            seg_qm_level: [15, 15, 15],
            uv_mode: 0,
        }
    }
}

/// §5.11.47 `transform_type( x4, y4, txSz )` outcome — the decoded
/// luma `TxType` ordinal plus the `TxTypes[ y4 + j ][ x4 + i ]`
/// grid-stamp footprint the caller writes back.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct TransformTypeReadout {
    /// The decoded `TxType` ordinal (`DCT_DCT..H_FLIPADST`).
    pub tx_type: u8,
    /// `Tx_Width[ txSz ] >> 2` — the number of 4×4 luma columns the
    /// caller stamps `TxTypes[ y4 + j ][ x4 + i ] = TxType` over.
    pub w4: u8,
    /// `Tx_Height[ txSz ] >> 2` — the number of 4×4 luma rows the
    /// caller stamps over.
    pub h4: u8,
}

/// `Tx_Size_Sqr` ordinal index. Used to look up the §8.3.2
/// `intra_tx_type` / `inter_tx_type` CDF row.
#[inline]
fn tx_size_sqr_index(tx_size: usize) -> usize {
    // `Tx_Size_Sqr` per §3 maps each `TX_SIZES_ALL` ordinal to a
    // square `TX_4X4..TX_64X64` ordinal (matching
    // `Min( Tx_Width, Tx_Height )` with the log2(side) - 2 rule).
    // The square `TX_NxN` ordinal is `log2(side) - 2` because
    // `TX_4X4 = 0`, `TX_8X8 = 1`, `TX_16X16 = 2`, `TX_32X32 = 3`,
    // `TX_64X64 = 4`.
    let side = core::cmp::min(TX_WIDTH[tx_size], TX_HEIGHT[tx_size]);
    (side.trailing_zeros() as usize) - 2
}

impl PartitionWalker {
    /// `transform_type( x4, y4, txSz )` per §5.11.47 (av1-spec p.99-100).
    /// Decodes the per-luma-TU `TxType` from the bitstream and emits
    /// the value the caller stamps into `TxTypes[ y4 + j ][ x4 + i ]`.
    ///
    /// The spec body reads:
    ///
    /// ```text
    ///   set = get_tx_set( txSz )
    ///   if ( set > 0 && (segmentation_enabled ? get_qindex(1, segment_id) : base_q_idx) > 0 ) {
    ///       if ( is_inter ) {
    ///           inter_tx_type   S()
    ///           TxType = Tx_Type_Inter_Inv_Set{1,2,3}[ inter_tx_type ]
    ///       } else {
    ///           intra_tx_type   S()
    ///           TxType = Tx_Type_Intra_Inv_Set{1,2}[ intra_tx_type ]
    ///       }
    ///   } else {
    ///       TxType = DCT_DCT
    ///   }
    ///   for ( i = 0; i < (Tx_Width[txSz] >> 2); i++ )
    ///     for ( j = 0; j < (Tx_Height[txSz] >> 2); j++ )
    ///         TxTypes[ y4 + j ][ x4 + i ] = TxType
    /// ```
    ///
    /// The `set > 0 && ((segmentation_enabled ? get_qindex(1,
    /// segment_id) : base_q_idx) > 0)` guard short-circuits to
    /// `DCT_DCT` on the §5.11.48 `TX_SET_DCTONLY` path AND on the
    /// "qindex is zero ⇒ no transform-type symbol" path; the spec
    /// inversion tables [`TX_TYPE_INTRA_INV_SET1`] /
    /// [`TX_TYPE_INTRA_INV_SET2`] / [`TX_TYPE_INTER_INV_SET1`] /
    /// [`TX_TYPE_INTER_INV_SET2`] / [`TX_TYPE_INTER_INV_SET3`] map
    /// the per-set symbol ordinal back into the §3 `TxType`
    /// enumeration.
    ///
    /// `intra_dir` is the §8.3.2 [`intra_dir`] result (the per-plane
    /// `intraDir` axis the §8.3.2 `intra_tx_type` CDF uses); for
    /// inter blocks the axis is unused.
    ///
    /// The caller is responsible for writing the returned
    /// `tx_type` over the `(w4, h4)` 4×4-luma footprint of the TU into
    /// the walker's `TxTypes[][]` grid (use [`Self::stamp_tx_type`]).
    #[allow(clippy::too_many_arguments)]
    pub fn transform_type(
        &mut self,
        decoder: &mut crate::symbol_decoder::SymbolDecoder<'_>,
        cdfs: &mut TileCdfContext,
        tx_size: usize,
        is_inter: bool,
        intra_dir: usize,
        reduced_tx_set: bool,
        segment_id: u8,
        quant: &QuantizerParams,
    ) -> Result<TransformTypeReadout, crate::Error> {
        if tx_size >= TX_SIZES_ALL {
            return Err(crate::Error::PartitionWalkOutOfRange);
        }
        // §5.11.48 `get_tx_set( txSz )`. Compute `Tx_Size_Sqr[ txSz ]`
        // and `Tx_Size_Sqr_Up[ txSz ]` per §3.
        let tx_sz_sqr = tx_size_sqr_index(tx_size);
        let tx_sz_sqr_up = TX_SIZE_SQR_UP[tx_size];
        let set = if is_inter {
            inter_tx_type_set(tx_sz_sqr as u32, tx_sz_sqr_up as u32, reduced_tx_set)
        } else {
            intra_tx_type_set(tx_sz_sqr as u32, tx_sz_sqr_up as u32, reduced_tx_set)
        };

        // §5.11.47 `(segmentation_enabled ? get_qindex(1, segment_id)
        // : base_q_idx) > 0` guard — `ignoreDeltaQ = 1` in the §7.12.2
        // qindex lookup (delta-q is intentionally ignored here).
        let q_for_guard = if quant.segmentation_enabled {
            get_qindex(quant, true, segment_id)
        } else {
            quant.base_q_idx as i32
        };
        let codes_symbol = set > 0 && q_for_guard > 0;

        let tx_type: u8 = if !codes_symbol {
            DCT_DCT as u8
        } else if is_inter {
            let sqr = tx_size_sqr_index(tx_size);
            let cdf = cdfs.inter_tx_type_cdf(set, sqr as u32).ok_or(
                // Should never happen on the conformant path —
                // `inter_tx_type_set` returns one of {DCTONLY, 1, 2,
                // 3}, and `inter_tx_type_cdf` only returns `None` for
                // DCTONLY (which the `codes_symbol == false` guard
                // above catches first).
                crate::Error::PartitionWalkOutOfRange,
            )?;
            let raw = decoder
                .read_symbol(cdf)
                .map_err(|_| crate::Error::UnexpectedEnd)? as usize;
            let table: &[usize] = match set {
                TX_SET_INTER_1 => &TX_TYPE_INTER_INV_SET1,
                TX_SET_INTER_2 => &TX_TYPE_INTER_INV_SET2,
                TX_SET_INTER_3 => &TX_TYPE_INTER_INV_SET3,
                _ => return Err(crate::Error::PartitionWalkOutOfRange),
            };
            // Symbol values must index inside the inversion table —
            // a conformant bitstream stays in `0..table.len()`.
            if raw >= table.len() {
                return Err(crate::Error::PartitionWalkOutOfRange);
            }
            table[raw] as u8
        } else {
            let sqr = tx_size_sqr_index(tx_size);
            let cdf = cdfs
                .intra_tx_type_cdf(set, sqr as u32, intra_dir)
                .ok_or(crate::Error::PartitionWalkOutOfRange)?;
            let raw = decoder
                .read_symbol(cdf)
                .map_err(|_| crate::Error::UnexpectedEnd)? as usize;
            let table: &[usize] = match set {
                TX_SET_INTRA_1 => &TX_TYPE_INTRA_INV_SET1,
                TX_SET_INTRA_2 => &TX_TYPE_INTRA_INV_SET2,
                _ => return Err(crate::Error::PartitionWalkOutOfRange),
            };
            if raw >= table.len() {
                return Err(crate::Error::PartitionWalkOutOfRange);
            }
            table[raw] as u8
        };

        let w4 = (TX_WIDTH[tx_size] >> 2) as u8;
        let h4 = (TX_HEIGHT[tx_size] >> 2) as u8;
        Ok(TransformTypeReadout { tx_type, w4, h4 })
    }

    /// Stamp `TxTypes[ y4 + j ][ x4 + i ] = tx_type` over a
    /// `(w4, h4)` 4×4-luma-sample-unit footprint anchored at
    /// `(x4, y4)`. Used by §5.11.39 (`all_zero == 1` ⇒ `DCT_DCT`
    /// fill), §5.11.47 (decoded `TxType` fill), and on the §5.11.40
    /// `compute_tx_type()` chroma path the §5.11.39 `all_zero` arm
    /// pre-stamps for.
    ///
    /// `x4` / `y4` are in 4×4-luma units (i.e. mi-units with
    /// `MI_SIZE_LOG2 == 2`). Cells outside the `mi_rows * mi_cols`
    /// grid bound are silently dropped (matches the §5.11.39 spec
    /// behaviour for a TU clipped against the bottom/right frame
    /// edge — those cells are unreachable for any subsequent
    /// `TxTypes[][]` read).
    pub fn stamp_tx_type(&mut self, x4: u32, y4: u32, w4: u32, h4: u32, tx_type: u8) {
        for j in 0..h4 {
            let row = y4 + j;
            if row >= self.mi_rows {
                break;
            }
            for i in 0..w4 {
                let col = x4 + i;
                if col >= self.mi_cols {
                    break;
                }
                let idx = (row * self.mi_cols + col) as usize;
                self.tx_types[idx] = tx_type;
            }
        }
    }

    /// Read `TxTypes[ y4 ][ x4 ]` from the walker's grid. Returns the
    /// `DCT_DCT = 0` pre-fill for cells the §5.11.39 / §5.11.47
    /// readers have not yet stamped.
    #[inline]
    pub fn tx_type_at(&self, y4: i32, x4: i32) -> u8 {
        if y4 < 0 || x4 < 0 || (y4 as u32) >= self.mi_rows || (x4 as u32) >= self.mi_cols {
            return DCT_DCT as u8;
        }
        self.tx_types[(y4 as u32 * self.mi_cols + x4 as u32) as usize]
    }
}

/// §8.3.2 `get_tx_class( txType )` — maps a transform type to its
/// transform class. The vertical-only types (`V_DCT` / `V_ADST` /
/// `V_FLIPADST`) return [`TX_CLASS_VERT`]; the horizontal-only types
/// (`H_DCT` / `H_ADST` / `H_FLIPADST`) return [`TX_CLASS_HORIZ`]; every
/// other transform type returns [`TX_CLASS_2D`].
///
/// The transform-type enumeration values are the §3 `*_DCT` / `*_ADST`
/// / `*_FLIPADST` constants; `v_dct` / `v_adst` / `v_flipadst` and
/// `h_dct` / `h_adst` / `h_flipadst` flag the directional types. The
/// full §8.3.2 `compute_tx_type()` derivation that produces `txType`
/// from the bitstream belongs to the tile-content walk; this helper
/// performs only the class reduction.
pub fn get_tx_class(
    v_dct: bool,
    v_adst: bool,
    v_flipadst: bool,
    h_dct: bool,
    h_adst: bool,
    h_flipadst: bool,
) -> usize {
    if v_dct || v_adst || v_flipadst {
        TX_CLASS_VERT
    } else if h_dct || h_adst || h_flipadst {
        TX_CLASS_HORIZ
    } else {
        TX_CLASS_2D
    }
}

/// §8.3.2 `get_coeff_base_ctx( txSz, plane, blockX, blockY, pos, c,
/// isEob )` — the `coeff_base` / `coeff_base_eob` neighbour-derivation.
///
/// ```text
///   adjTxSz = Adjusted_Tx_Size[ txSz ]
///   bwl     = Tx_Width_Log2[ adjTxSz ]
///   width   = 1 << bwl
///   height  = Tx_Height[ adjTxSz ]
///   if ( isEob ) {                       // EOB-position buckets
///       if ( c == 0 )                  return SIG_COEF_CONTEXTS - 4
///       if ( c <= (height<<bwl)/8 )    return SIG_COEF_CONTEXTS - 3
///       if ( c <= (height<<bwl)/4 )    return SIG_COEF_CONTEXTS - 2
///                                      return SIG_COEF_CONTEXTS - 1
///   }
///   row = pos >> bwl ;  col = pos - (row << bwl)
///   mag = sum over SIG_REF_DIFF_OFFSET_NUM neighbours of
///         Min( Abs( Quant[(refRow<<bwl)+refCol] ), 3 )      // in-bounds only
///   ctx = Min( (mag + 1) >> 1, 4 )
///   if ( txClass == TX_CLASS_2D ) {
///       if ( row == 0 && col == 0 )  return 0
///       return ctx + Coeff_Base_Ctx_Offset[ txSz ][ Min(row,4) ][ Min(col,4) ]
///   }
///   idx = (txClass == TX_CLASS_VERT) ? row : col
///   return ctx + Coeff_Base_Pos_Ctx_Offset[ Min(idx, 2) ]
/// ```
///
/// The neighbour scan uses [`SIG_REF_DIFF_OFFSET`] with the bound check
/// `refRow < height && refCol < width` (`width = 1 << bwl`); the
/// `Coeff_Base_Ctx_Offset` lookup uses the *original* `tx_size`, not the
/// adjusted size. `quant` is the coefficient-magnitude array (`Quant`)
/// indexed `(refRow << bwl) + refCol`; `tx_class` is the
/// [`get_tx_class`] result supplied by the caller (the
/// `compute_tx_type()` derivation belongs to the tile walk); `pos` is
/// the scan position `scan[c]`; `c` is the scan index; `is_eob` selects
/// the EOB-position buckets.
///
/// Returns a value in `0..SIG_COEF_CONTEXTS` (the EOB buckets occupy the
/// top four). The `coeff_base_eob` selector applies
/// `- SIG_COEF_CONTEXTS + SIG_COEF_CONTEXTS_EOB` to map onto
/// `0..SIG_COEF_CONTEXTS_EOB` — see [`get_coeff_base_eob_ctx`].
pub fn get_coeff_base_ctx(
    quant: &[i32],
    tx_size: usize,
    tx_class: usize,
    pos: usize,
    c: usize,
    is_eob: bool,
) -> usize {
    let adj_tx_sz = ADJUSTED_TX_SIZE[tx_size];
    let bwl = TX_WIDTH_LOG2[adj_tx_sz];
    let width = 1usize << bwl;
    let height = TX_HEIGHT[adj_tx_sz];

    if is_eob {
        if c == 0 {
            return SIG_COEF_CONTEXTS - 4;
        }
        if c <= (height << bwl) / 8 {
            return SIG_COEF_CONTEXTS - 3;
        }
        if c <= (height << bwl) / 4 {
            return SIG_COEF_CONTEXTS - 2;
        }
        return SIG_COEF_CONTEXTS - 1;
    }

    let row = pos >> bwl;
    let col = pos - (row << bwl);

    // Accumulate the neighbour magnitude over the SIG_REF_DIFF_OFFSET_NUM
    // offsets, clamping each in-bounds neighbour magnitude to 3.
    let mut mag: i32 = 0;
    for offset in &SIG_REF_DIFF_OFFSET[tx_class] {
        let ref_row = row + offset[0];
        let ref_col = col + offset[1];
        // The offsets are non-negative, so refRow / refCol >= 0 holds by
        // construction; only the upper bound needs checking.
        if ref_row < height && ref_col < width {
            let q = quant[(ref_row << bwl) + ref_col].unsigned_abs() as i32;
            mag += q.min(3);
        }
    }

    let ctx = (((mag + 1) >> 1).min(4)) as usize;

    if tx_class == TX_CLASS_2D {
        if row == 0 && col == 0 {
            return 0;
        }
        return ctx + COEFF_BASE_CTX_OFFSET[tx_size][row.min(4)][col.min(4)];
    }
    let idx = if tx_class == TX_CLASS_VERT { row } else { col };
    ctx + COEFF_BASE_POS_CTX_OFFSET[idx.min(2)]
}

/// §8.3.2 `coeff_base_eob` context: the [`get_coeff_base_ctx`] result
/// with `is_eob = true`, reduced onto `0..SIG_COEF_CONTEXTS_EOB` via
/// `ctx - SIG_COEF_CONTEXTS + SIG_COEF_CONTEXTS_EOB`. The result is the
/// `ctx` index consumed by [`TileCdfContext::coeff_base_eob_cdf`].
pub fn get_coeff_base_eob_ctx(
    quant: &[i32],
    tx_size: usize,
    tx_class: usize,
    pos: usize,
    c: usize,
) -> usize {
    // The §8.3.2 reduction is `ctx - SIG_COEF_CONTEXTS + SIG_COEF_CONTEXTS_EOB`
    // in signed arithmetic. The isEob path returns a value in
    // `SIG_COEF_CONTEXTS-4 ..= SIG_COEF_CONTEXTS-1`, so adding the EOB
    // context count first keeps the intermediate non-negative for usize.
    (get_coeff_base_ctx(quant, tx_size, tx_class, pos, c, true) + SIG_COEF_CONTEXTS_EOB)
        - SIG_COEF_CONTEXTS
}

/// §8.3.2 `get_br_ctx` — the `coeff_br` neighbour-derivation.
///
/// ```text
///   adjTxSz = Adjusted_Tx_Size[ txSz ]
///   bwl = Tx_Width_Log2[ adjTxSz ] ; txw = Tx_Width[ adjTxSz ]
///   txh = Tx_Height[ adjTxSz ]
///   row = pos >> bwl ; col = pos - (row << bwl)
///   mag = sum over 3 neighbours of
///         Min( Quant[refRow*txw+refCol], COEFF_BASE_RANGE+NUM_BASE_LEVELS+1 )
///   mag = Min( (mag + 1) >> 1, 6 )
///   if ( pos == 0 )                       ctx = mag
///   else if ( txClass == 0 )              ctx = mag + (row<2 && col<2 ? 7 : 14)
///   else if ( txClass == 1 )              ctx = mag + (col==0 ? 7 : 14)
///   else                                  ctx = mag + (row==0 ? 7 : 14)
/// ```
///
/// The neighbour scan uses [`MAG_REF_OFFSET_WITH_TX_CLASS`] (three
/// offsets) with the bound check `refRow < txh && refCol < (1 << bwl)`.
/// Note the magnitude is `Quant[..]` directly (not its absolute value)
/// and the clamp is `COEFF_BASE_RANGE + NUM_BASE_LEVELS + 1`, distinct
/// from the `get_coeff_base_ctx()` scan. `quant` is the
/// coefficient-magnitude array indexed `refRow * txw + refCol`;
/// `tx_class` is the [`get_tx_class`] result supplied by the caller;
/// `pos` is the scan position.
///
/// Returns a value in `0..LEVEL_CONTEXTS`, the `ctx` index consumed by
/// [`TileCdfContext::coeff_br_cdf`].
pub fn get_br_ctx(quant: &[i32], tx_size: usize, tx_class: usize, pos: usize) -> usize {
    let adj_tx_sz = ADJUSTED_TX_SIZE[tx_size];
    let bwl = TX_WIDTH_LOG2[adj_tx_sz];
    let txw = TX_WIDTH[adj_tx_sz];
    let txh = TX_HEIGHT[adj_tx_sz];
    let row = pos >> bwl;
    let col = pos - (row << bwl);

    let clamp = (COEFF_BASE_RANGE + NUM_BASE_LEVELS + 1) as i32;
    let mut mag: i32 = 0;
    for offset in &MAG_REF_OFFSET_WITH_TX_CLASS[tx_class] {
        let ref_row = row + offset[0];
        let ref_col = col + offset[1];
        if ref_row < txh && ref_col < (1usize << bwl) {
            mag += quant[ref_row * txw + ref_col].min(clamp);
        }
    }

    let mag = (((mag + 1) >> 1).min(6)) as usize;
    if pos == 0 {
        mag
    } else if tx_class == TX_CLASS_2D {
        if row < 2 && col < 2 {
            mag + 7
        } else {
            mag + 14
        }
    } else if tx_class == TX_CLASS_HORIZ {
        if col == 0 {
            mag + 7
        } else {
            mag + 14
        }
    } else if row == 0 {
        mag + 7
    } else {
        mag + 14
    }
}

// ---------------------------------------------------------------------
// Round 143 — inter-intra group (§9.4): `Default_Inter_Intra_Cdf`,
// `Default_Inter_Intra_Mode_Cdf`, `Default_Wedge_Inter_Intra_Cdf`. All
// three CDFs are read by the §5.11.28 `read_interintra_mode` syntax
// inside the inter-block mode-info parse (the `interintra`,
// `interintra_mode`, and `wedge_interintra` elements). §6.10.27 enumerates
// `INTERINTRA_MODES = 4` values for `interintra_mode` (`II_DC_PRED`,
// `II_V_PRED`, `II_H_PRED`, `II_SMOOTH_PRED`).
//
// §8.3.2 selection for `interintra` / `interintra_mode` is
// `ctx = Size_Group[ MiSize ] - 1`; the §5.11.28 gate confines coded
// blocks to the `BLOCK_8X8`..`BLOCK_32X32` band, so the resulting `ctx`
// is one of `{0, 1, 2}` — matching the `[ BLOCK_SIZE_GROUPS - 1 ]` outer
// dimension. The §8.3.2 `wedge_interintra` selection is a straight
// `TileWedgeInterIntraCdf[ MiSize ]` index; per the §9.4 note only block
// sizes 3..=9 (the BLOCK_8X8..BLOCK_32X32 band) are reachable, but the
// table is transcribed full-width to keep the indexing uniform with
// every other `[ BLOCK_SIZES ]` table.
// ---------------------------------------------------------------------

/// `Default_Inter_Intra_Cdf[ BLOCK_SIZE_GROUPS - 1 ][ 3 ]` (§9.4). Binary
/// symbol `interintra` (§5.11.28 `read_interintra_mode` gate; selects
/// whether an inter prediction should be blended with an intra prediction,
/// per §6.10.27 semantics). The §8.3.2 selection computes
/// `ctx = Size_Group[ MiSize ] - 1` (the spec's literal text), valid in
/// `0..(BLOCK_SIZE_GROUPS - 1)`. Each row carries two cumulative
/// frequencies plus the §8.3 adaptation counter (starts at 0).
pub const DEFAULT_INTER_INTRA_CDF: [[u16; 3]; BLOCK_SIZE_GROUPS - 1] =
    [[26887, 32768, 0], [27597, 32768, 0], [30237, 32768, 0]];

/// `Default_Inter_Intra_Mode_Cdf[ BLOCK_SIZE_GROUPS - 1 ][ INTERINTRA_MODES + 1 ]`
/// (§9.4). Codes `interintra_mode ∈ { II_DC_PRED, II_V_PRED, II_H_PRED,
/// II_SMOOTH_PRED }` (§6.10.27 enumeration). The §8.3.2 selection
/// computes `ctx = Size_Group[ MiSize ] - 1`, valid in
/// `0..(BLOCK_SIZE_GROUPS - 1)`. Each row carries
/// `INTERINTRA_MODES = 4` cumulative frequencies plus the §8.3 adaptation
/// counter (starts at 0).
pub const DEFAULT_INTER_INTRA_MODE_CDF: [[u16; INTERINTRA_MODES + 1]; BLOCK_SIZE_GROUPS - 1] = [
    [1875, 11082, 27332, 32768, 0],
    [2473, 9996, 26388, 32768, 0],
    [4238, 11537, 25926, 32768, 0],
];

/// `Default_Wedge_Inter_Intra_Cdf[ BLOCK_SIZES ][ 3 ]` (§9.4). Binary
/// symbol `wedge_interintra` (§5.11.28; §6.10.27 selects whether wedge
/// blending should be used). The §8.3.2 selection is a straight
/// `TileWedgeInterIntraCdf[ MiSize ]` index. Per the §9.4 note only
/// indices 3..=9 (the `BLOCK_8X8`..`BLOCK_32X32` band — the same band
/// the §5.11.28 syntax gate confines coded blocks to) are ever used in
/// the first dimension; the rows outside that band are placeholder
/// `{16384, 32768, 0}` entries and are transcribed full-width to keep
/// `MiSize`-indexing uniform with every other `[ BLOCK_SIZES ]` table.
pub const DEFAULT_WEDGE_INTER_INTRA_CDF: [[u16; 3]; BLOCK_SIZES] = [
    [16384, 32768, 0],
    [16384, 32768, 0],
    [16384, 32768, 0],
    [20036, 32768, 0],
    [24957, 32768, 0],
    [26704, 32768, 0],
    [27530, 32768, 0],
    [29564, 32768, 0],
    [29444, 32768, 0],
    [26872, 32768, 0],
    [16384, 32768, 0],
    [16384, 32768, 0],
    [16384, 32768, 0],
    [16384, 32768, 0],
    [16384, 32768, 0],
    [16384, 32768, 0],
    [16384, 32768, 0],
    [16384, 32768, 0],
    [16384, 32768, 0],
    [16384, 32768, 0],
    [16384, 32768, 0],
    [16384, 32768, 0],
];

/// §8.3.2 `interintra` / `interintra_mode` context mapping:
/// `ctx = Size_Group[ MiSize ] - 1`. The result selects a
/// [`TileCdfContext::inter_intra_cdf`] /
/// [`TileCdfContext::inter_intra_mode_cdf`] row and is in
/// `0..(BLOCK_SIZE_GROUPS - 1)`. `mi_size` is the current block's `MiSize`
/// (`0..BLOCK_SIZES`).
///
/// The §5.11.28 syntax gate restricts coded blocks to
/// `BLOCK_8X8 <= MiSize <= BLOCK_32X32` (per §6.10.27), where
/// `Size_Group[ MiSize ]` is one of `{1, 2, 3}` and the subtraction is
/// well-defined. Returns `None` if `Size_Group[ MiSize ] == 0` (a caller
/// bug: the §5.11.28 gate would not have coded `interintra` /
/// `interintra_mode` in that case) or if `mi_size >= BLOCK_SIZES`.
pub fn interintra_ctx(mi_size: usize) -> Option<usize> {
    if mi_size >= BLOCK_SIZES {
        return None;
    }
    let g = SIZE_GROUP[mi_size];
    if g == 0 {
        None
    } else {
        Some(g - 1)
    }
}

/// §8.3.2 `comp_group_idx` context selection (av1-spec p.384). The
/// spec body reads:
///
/// ```text
///   ctx = 0
///   if ( AvailU ) {
///     if ( !AboveSingle )
///       ctx += CompGroupIdxs[ MiRow - 1 ][ MiCol ]
///     else if ( AboveRefFrame[ 0 ] == ALTREF_FRAME )
///       ctx += 3
///   }
///   if ( AvailL ) {
///     if ( !LeftSingle )
///       ctx += CompGroupIdxs[ MiRow ][ MiCol - 1 ]
///     else if ( LeftRefFrame[ 0 ] == ALTREF_FRAME )
///       ctx += 3
///   }
///   ctx = Min( 5, ctx )
/// ```
///
/// `above_comp_group` / `left_comp_group` are the neighbour
/// `CompGroupIdxs` values (binary `0` or `1`); they're only consulted
/// on the `!AboveSingle` / `!LeftSingle` arm.
///
/// `above_ref_0_altref` / `left_ref_0_altref` carry the
/// `RefFrame[ 0 ] == ALTREF_FRAME = 7` test, only consulted on the
/// `AboveSingle` / `LeftSingle` arm.
///
/// Returns a value in `0..COMP_GROUP_IDX_CONTEXTS` (`= 0..6`); the
/// final `Min( 5, ctx )` clamp is applied here.
#[inline]
#[must_use]
#[allow(clippy::too_many_arguments)]
pub fn comp_group_idx_ctx(
    avail_u: bool,
    above_single: bool,
    above_comp_group: u8,
    above_ref_0_altref: bool,
    avail_l: bool,
    left_single: bool,
    left_comp_group: u8,
    left_ref_0_altref: bool,
) -> usize {
    let mut ctx: usize = 0;
    if avail_u {
        if !above_single {
            ctx += above_comp_group as usize;
        } else if above_ref_0_altref {
            ctx += 3;
        }
    }
    if avail_l {
        if !left_single {
            ctx += left_comp_group as usize;
        } else if left_ref_0_altref {
            ctx += 3;
        }
    }
    if ctx > 5 {
        5
    } else {
        ctx
    }
}

/// §8.3.2 `compound_idx` context selection (av1-spec p.384). The spec
/// body reads:
///
/// ```text
///   fwd = Abs( get_relative_dist( OrderHints[ RefFrame[ 0 ] ], OrderHint ) )
///   bck = Abs( get_relative_dist( OrderHints[ RefFrame[ 1 ] ], OrderHint ) )
///   ctx = ( fwd == bck ) ? 3 : 0
///   if ( AvailU ) {
///     if ( !AboveSingle )
///       ctx += CompoundIdxs[ MiRow - 1 ][ MiCol ]
///     else if ( AboveRefFrame[ 0 ] == ALTREF_FRAME )
///       ctx++
///   }
///   if ( AvailL ) {
///     if ( !LeftSingle )
///       ctx += CompoundIdxs[ MiRow ][ MiCol - 1 ]
///     else if ( LeftRefFrame[ 0 ] == ALTREF_FRAME )
///       ctx++
///   }
/// ```
///
/// `dist_equal` is the `fwd == bck` outcome the caller computed via
/// §7.8.1 `get_relative_dist` against the resolved `OrderHints[]` /
/// `OrderHint` frame-header state.
///
/// `above_compound` / `left_compound` are the neighbour `CompoundIdxs`
/// values (binary `0` or `1`); they're only consulted on the
/// `!AboveSingle` / `!LeftSingle` arm.
///
/// `above_ref_0_altref` / `left_ref_0_altref` carry the
/// `RefFrame[ 0 ] == ALTREF_FRAME = 7` test, only consulted on the
/// `AboveSingle` / `LeftSingle` arm.
///
/// Returns a value in `0..COMPOUND_IDX_CONTEXTS` (`= 0..6`): the
/// maximum is `3 (dist_equal) + 1 (above) + 1 (left) = 5`, the
/// minimum is `0`. The spec body does not apply a `Min(..)` clamp —
/// the cap is structural.
#[inline]
#[must_use]
#[allow(clippy::too_many_arguments)]
pub fn compound_idx_ctx(
    dist_equal: bool,
    avail_u: bool,
    above_single: bool,
    above_compound: u8,
    above_ref_0_altref: bool,
    avail_l: bool,
    left_single: bool,
    left_compound: u8,
    left_ref_0_altref: bool,
) -> usize {
    let mut ctx: usize = if dist_equal { 3 } else { 0 };
    if avail_u {
        if !above_single {
            ctx += above_compound as usize;
        } else if above_ref_0_altref {
            ctx += 1;
        }
    }
    if avail_l {
        if !left_single {
            ctx += left_compound as usize;
        } else if left_ref_0_altref {
            ctx += 1;
        }
    }
    debug_assert!(
        ctx < COMPOUND_IDX_CONTEXTS,
        "compound_idx ctx must be in 0..COMPOUND_IDX_CONTEXTS"
    );
    ctx
}

