        let mut dec = SymbolDecoder::init_symbol(&bytes, 4, false).unwrap();
        let mut tile_ctx = TileCdfContext::new_from_defaults();
        let before = tile_ctx.wedge_index;

        // MiSize = 6 (BLOCK_16X16): Wedge_Bits[6] = 4, so wedge_index is
