    /// Forced PARTITION_SPLIT at BLOCK_16X16 with all sub-BLOCK_8X8
    /// children forced to PARTITION_NONE: 4 leaves of BLOCK_8X8 in
    /// the spec's documented quadrant order.
    #[test]
    fn decode_partition_forced_split_recurses_to_4_leaves() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        // Top-level BLOCK_16X16 → PARTITION_SPLIT.
        let rigged_w16 = force_partition_cdf_w(PARTITION_SPLIT, 10);
        for ctx_idx in 0..PARTITION_CONTEXTS {
            cdfs.partition_w16[ctx_idx].copy_from_slice(&rigged_w16);
        }
        // Each BLOCK_8X8 child → PARTITION_NONE (W8 row has 5 symbols).
        let rigged_w8 = force_partition_cdf_w(PARTITION_NONE, 4);
        for ctx_idx in 0..PARTITION_CONTEXTS {
            cdfs.partition_w8[ctx_idx].copy_from_slice(&rigged_w8);
        }
        let bytes = [0u8; 64];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 64, true).unwrap();
        walker
            .decode_partition(&mut dec, &mut cdfs, 0, 0, BLOCK_16X16)
            .unwrap();
        assert_eq!(walker.blocks().len(), 4);
        for blk in walker.blocks() {
            assert_eq!(blk.sub_size, BLOCK_8X8);
        }
        // §5.11.4 quadrant order: (r,c), (r,c+half), (r+half,c),
        // (r+half,c+half).
        assert_eq!(walker.blocks()[0].mi_row, 0);
        assert_eq!(walker.blocks()[0].mi_col, 0);
        assert_eq!(walker.blocks()[1].mi_row, 0);
        assert_eq!(walker.blocks()[1].mi_col, 2);
        assert_eq!(walker.blocks()[2].mi_row, 2);
        assert_eq!(walker.blocks()[2].mi_col, 0);
        assert_eq!(walker.blocks()[3].mi_row, 2);
        assert_eq!(walker.blocks()[3].mi_col, 2);
    }

    /// §6.10.4 grid-fill: after a forced PARTITION_HORZ at
    /// BLOCK_16X16, every cell of the two BLOCK_16X8 leaves' `bh4 *
    /// bw4` footprints carries `BLOCK_16X8`, and adjacent cells stay
    /// `BLOCK_INVALID`.
    #[test]
    fn decode_partition_grid_fill_after_horz() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let rigged = force_partition_cdf_w(PARTITION_HORZ, 10);
        for ctx_idx in 0..PARTITION_CONTEXTS {
            cdfs.partition_w16[ctx_idx].copy_from_slice(&rigged);
        }
        let bytes = [0u8; 16];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 16, true).unwrap();
        walker
            .decode_partition(&mut dec, &mut cdfs, 0, 0, BLOCK_16X16)
            .unwrap();

        // BLOCK_16X8 footprint: bw4 = 4, bh4 = 2.
        // Top leaf at (0,0): MiSizes[0..2][0..4] = BLOCK_16X8.
        for r in 0..2 {
            for c in 0..4 {
                assert_eq!(
                    walker.mi_sizes()[r * 32 + c],
                    BLOCK_16X8,
                    "top leaf cell ({r},{c}) should be BLOCK_16X8"
                );
            }
        }
        // Bottom leaf at (2,0): MiSizes[2..4][0..4] = BLOCK_16X8.
        for r in 2..4 {
            for c in 0..4 {
                assert_eq!(walker.mi_sizes()[r * 32 + c], BLOCK_16X8);
            }
        }
        // Outside footprint stays BLOCK_INVALID.
        assert_eq!(walker.mi_sizes()[4], BLOCK_INVALID);
        assert_eq!(walker.mi_sizes()[4 * 32], BLOCK_INVALID);
    }

    /// Smoke test: a full walk against the §9.4 default CDFs at the
    /// W128 superblock size completes without error and emits
    /// well-formed leaves entirely inside the frame extent. The
    /// partition tree picked depends on the byte stream, but the
    /// invariants are independent.
    #[test]
    fn decode_partition_default_cdf_w128_smoke() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        // 128 bytes of bitstream — plenty for the partition tree's
        // worst-case depth.
        let bytes = [0x55u8; 128];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 128, true).unwrap();
        walker
            .decode_partition(&mut dec, &mut cdfs, 0, 0, BLOCK_128X128)
            .unwrap();
        // At least one leaf must be emitted.
        assert!(!walker.blocks().is_empty());
        // Every leaf is in-frame and has a valid sub_size.
        for blk in walker.blocks() {
            assert!(blk.sub_size < BLOCK_SIZES);
            assert!(blk.mi_row < 32);
            assert!(blk.mi_col < 32);
        }
        // Total mi area of leaves <= frame mi area (no double-counting).
        let total: u64 = walker
            .blocks()
            .iter()
            .map(|b| {
                (NUM_4X4_BLOCKS_WIDE[b.sub_size] as u64) * (NUM_4X4_BLOCKS_HIGH[b.sub_size] as u64)
            })
            .sum();
        assert!(total <= (32 * 32) as u64);
    }

    /// §8.3.2 partition_ctx derivation: the walker computes `above`
    /// and `left` against the §6.10.4 MiSizes grid populated by
    /// previously-decoded leaves. At the (0, 0) superblock, both
    /// AvailU and AvailL are false (the neighbour positions are
    /// outside the tile), so partition_ctx returns 0 regardless of
    /// neighbour state.
    #[test]
    fn partition_ctx_for_origin_is_zero() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let walker = PartitionWalker::new(32, 32, geom).unwrap();
        // For any bsl, (r=0, c=0) -> AvailU=false, AvailL=false -> ctx=0.
        for bsl in 1..=5 {
            assert_eq!(walker.partition_ctx_for(0, 0, bsl), 0);
        }
    }

    /// `partition_ctx_for` after a leaf decode: if a wider neighbour
    /// is present, the §8.3.2 `Mi_Width_Log2[ ... ] < bsl` test fails
    /// (neighbour width >= bsl) and the corresponding bit stays
    /// `false`.
    #[test]
    fn partition_ctx_for_wide_neighbour_drops_bit() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        // Fill row 0 with BLOCK_16X16 (mi_width_log2 = 2) so the
        // above-neighbour at (1, 0) is BLOCK_16X16.
        walker.decode_block(0, 0, BLOCK_16X16);
        // At (4, 0) with bsl = 2 (W16): AvailU=true (4-1=3 inside),
        // above_neighbour at (3, 0) is BLOCK_INVALID (BLOCK_16X16
        // footprint is only rows 0..4, cols 0..4 — (3,0) IS in the
        // footprint, so MiSizes[3][0] = BLOCK_16X16). With
        // mi_width_log2[BLOCK_16X16] = 2 and bsl = 2, the test
        // (2 < 2) is false ⇒ above bit = false.
        // AvailL=true at (4, 0) ⇒ left col is -1 ⇒ is_inside false ⇒
        // left = false.
        // Actually with mi_col -1, is_inside is false ⇒ AvailL=false ⇒
        // left=false.
        // ctx should be 0.
        assert_eq!(walker.partition_ctx_for(4, 0, 2), 0);

        // At (4, 4) with bsl = 1 (W8): AvailU=true (3 inside),
        // above_neighbour at (3, 4) is BLOCK_INVALID (outside the
        // 16x16 footprint at col 4). BLOCK_INVALID > BLOCK_SIZES, so
        // the check `nb < BLOCK_SIZES` is false ⇒ above = false.
        // AvailL=true (3 inside), left_neighbour at (4, 3) is also
        // outside the BLOCK_16X16 footprint (rows 0..4) ⇒
        // BLOCK_INVALID ⇒ left = false.
        // ctx = 0.
        assert_eq!(walker.partition_ctx_for(4, 4, 1), 0);

        // At (4, 0) with bsl = 3 (W32): above_neighbour at (3, 0) is
        // BLOCK_16X16 with mi_width_log2 = 2. 2 < 3 ⇒ above = true.
        // left = false. ctx = (false as 2) + (true as 1) = 1.
        assert_eq!(walker.partition_ctx_for(4, 0, 3), 1);
    }

    /// Construction sanity: PartitionWalker::new with absurd
    /// dimensions returns None.
    #[test]
    fn partition_walker_construction_overflow() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: u32::MAX,
            mi_col_start: 0,
            mi_col_end: u32::MAX,
        };
        // mi_rows * mi_cols overflows usize on this platform.
        assert!(PartitionWalker::new(u32::MAX, u32::MAX, geom).is_none());
    }

    /// `take_blocks` drains and resets the internal buffer.
    #[test]
    fn take_blocks_drains_buffer() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let bytes = [0u8; 1];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 1, true).unwrap();
        walker
            .decode_partition(&mut dec, &mut cdfs, 0, 0, BLOCK_4X4)
            .unwrap();
        assert_eq!(walker.blocks().len(), 1);
        let drained = walker.take_blocks();
        assert_eq!(drained.len(), 1);
        assert!(walker.blocks().is_empty());
    }

    // -----------------------------------------------------------------
    // Round 152 — §5.11.11 read_skip walker tests.
    // -----------------------------------------------------------------

    /// Helper: force a 2-symbol CDF (here `skip_cdf[ctx]` which has
    /// length 3) to select `symbol` on the next `read_symbol`.
    /// `Default_Skip_Cdf` rows have shape `[a, 1 << 15, 0]`; the §8.2.6
    /// search returns the first symbol whose cumulative `cur > 0` is
    /// strictly below `SymbolValue`. With a freshly-initialised
    /// SymbolDecoder against zero bytes, `SymbolValue = 32767`; setting
    /// `cdf[symbol..N] = [1 << 15; N - symbol]` and `cdf[..symbol] = 0`
    /// puts `cur = 0` for every smaller symbol and `cur` near the top
    /// for the target.
    fn force_binary_cdf(symbol: u8) -> [u16; 3] {
        match symbol {
            0 => [1 << 15, 1 << 15, 0],
            1 => [0, 1 << 15, 0],
            _ => panic!("force_binary_cdf supports 0 or 1 only"),
        }
    }

    /// §5.11.11 first branch: `SegIdPreSkip && seg_feature_active(
    /// SEG_LVL_SKIP )` ⇒ `skip = 1`, no symbol read. The decoder
    /// position must not advance.
    #[test]
    fn decode_skip_seg_short_circuit_no_symbol_read() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let bytes = [0xFFu8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        let pos_before = dec.position();
        let skip = walker
            .decode_skip(&mut dec, &mut cdfs, 0, 0, BLOCK_16X16, true)
            .unwrap();
        assert_eq!(skip, 1, "seg_skip_active ⇒ skip = 1");
        assert_eq!(
            dec.position(),
            pos_before,
            "no symbol bit read on the seg short-circuit"
        );
    }

    /// §5.11.11 else branch with a rigged CDF forcing symbol 0
    /// (skip = 0): the decoder advances past the S() symbol and the
    /// returned value matches.
    #[test]
    fn decode_skip_else_branch_returns_symbol_zero() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        // Force every Skip ctx row to select symbol 0.
        let rigged = force_binary_cdf(0);
        for ctx_idx in 0..SKIP_CONTEXTS {
            cdfs.skip[ctx_idx] = rigged;
        }
        let bytes = [0u8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        let skip = walker
            .decode_skip(&mut dec, &mut cdfs, 0, 0, BLOCK_16X16, false)
            .unwrap();
        assert_eq!(skip, 0);
    }

    /// §5.11.11 else branch with a rigged CDF forcing symbol 1
    /// (skip = 1): the returned value matches and the value is stamped
    /// into the `Skips[]` grid over the block's `bh4 * bw4` footprint.
    #[test]
    fn decode_skip_else_branch_returns_symbol_one_and_stamps_grid() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let rigged = force_binary_cdf(1);
        for ctx_idx in 0..SKIP_CONTEXTS {
            cdfs.skip[ctx_idx] = rigged;
        }
        let bytes = [0u8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        let skip = walker
            .decode_skip(&mut dec, &mut cdfs, 0, 0, BLOCK_16X16, false)
            .unwrap();
        assert_eq!(skip, 1);

        // §5.11.5 grid-fill: BLOCK_16X16 has bw4 = bh4 = 4, so the
        // footprint Skips[0..4][0..4] all carry 1.
        for r in 0..4 {
            for c in 0..4 {
                assert_eq!(
                    walker.skips()[r * 32 + c],
                    1,
                    "footprint cell ({r},{c}) should be skip = 1",
                );
            }
        }
        // Cells outside the footprint stay at the initial 0.
        assert_eq!(walker.skips()[4], 0, "col 4 outside footprint");
        assert_eq!(walker.skips()[4 * 32], 0, "row 4 outside footprint");
    }

    /// §5.11.11 seg short-circuit also stamps the `Skips[]` grid
    /// footprint to 1 (the spec's §5.11.5 footer applies regardless of
    /// which branch produced the skip value).
    #[test]
    fn decode_skip_seg_short_circuit_stamps_grid() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let bytes = [0xFFu8; 1];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 1, true).unwrap();
        // BLOCK_8X8: bw4 = bh4 = 2. Place the block at (4, 6).
        walker
            .decode_skip(&mut dec, &mut cdfs, 4, 6, BLOCK_8X8, true)
            .unwrap();
        for dr in 0..2 {
            for dc in 0..2 {
                assert_eq!(walker.skips()[(4 + dr) * 32 + (6 + dc)], 1);
            }
        }
        // Adjacent cells stay at 0.
        assert_eq!(walker.skips()[3 * 32 + 6], 0);
        assert_eq!(walker.skips()[6 * 32 + 6], 0);
        assert_eq!(walker.skips()[4 * 32 + 5], 0);
        assert_eq!(walker.skips()[4 * 32 + 8], 0);
    }

    /// §8.3.2 skip-ctx walk: at the frame origin both AvailU and AvailL
    /// are false ⇒ ctx = 0. The chosen CDF row's first symbol fires.
    /// Test setup: skip_cdf[0] forced to select symbol 1, skip_cdf[1..]
    /// forced to select symbol 0 — confirms ctx = 0 was picked.
    #[test]
    fn decode_skip_origin_ctx_is_zero() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        cdfs.skip[0] = force_binary_cdf(1);
        cdfs.skip[1] = force_binary_cdf(0);
        cdfs.skip[2] = force_binary_cdf(0);
        let bytes = [0u8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        let skip = walker
            .decode_skip(&mut dec, &mut cdfs, 0, 0, BLOCK_8X8, false)
            .unwrap();
        assert_eq!(skip, 1, "origin selects skip_cdf[0] which forces 1");
    }

    /// §8.3.2 skip-ctx walk with two `Skips[]=1` neighbours: ctx = 2.
    /// Two prior `decode_skip` calls at (0, 0) and (0, 2) seed the
    /// above neighbour `Skips[0][2]=1` for the block at (2, 2), and
    /// the left neighbour `Skips[2][1]=1` via a separate (2, 0)
    /// BLOCK_8X8 leaf. The third call at (2, 2) should land on ctx =
    /// `Skips[1][2] + Skips[2][1] = 1 + 1 = 2`. We assert that by
    /// rigging skip_cdf[2] to force symbol 0 and skip_cdf[0..=1] to
    /// force symbol 1.
    #[test]
    fn decode_skip_ctx_sums_neighbour_skips() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        // First fill the two BLOCK_8X8 neighbour cells with skip = 1
        // via the seg short-circuit (so no symbol bits are consumed
        // before the ctx-2 read).
        let bytes = [0u8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        // Above neighbour: BLOCK_8X8 at (0, 2). Fills Skips[0..2][2..4]=1.
        walker
            .decode_skip(&mut dec, &mut cdfs, 0, 2, BLOCK_8X8, true)
            .unwrap();
        // Left neighbour: BLOCK_8X8 at (2, 0). Fills Skips[2..4][0..2]=1.
        walker
            .decode_skip(&mut dec, &mut cdfs, 2, 0, BLOCK_8X8, true)
            .unwrap();
        assert_eq!(walker.skips()[32 + 2], 1, "above neighbour seeded");
        assert_eq!(walker.skips()[2 * 32 + 1], 1, "left neighbour seeded");

        // Now rig CDFs so ctx = 2 reads as 0 and ctx in {0, 1} reads
        // as 1 — the actual ctx selected must be 2.
        cdfs.skip[0] = force_binary_cdf(1);
        cdfs.skip[1] = force_binary_cdf(1);
        cdfs.skip[2] = force_binary_cdf(0);
        let skip = walker
            .decode_skip(&mut dec, &mut cdfs, 2, 2, BLOCK_8X8, false)
            .unwrap();
        assert_eq!(skip, 0, "ctx = 2 was picked (skip_cdf[2] forces 0)");
    }

    /// §8.3.2 skip-ctx walk with one `Skips[]=1` above-neighbour and
    /// no left-neighbour available (`AvailL = false`): ctx = 1.
    /// Place the block at (1, 0) on a frame whose tile_col_start = 0:
    /// left-neighbour col = -1 is outside the tile ⇒ AvailL = false ⇒
    /// left contributes 0. Above-neighbour is the (0, 0) block, seeded
    /// with skip = 1 ⇒ above contributes 1.
    #[test]
    fn decode_skip_avail_l_false_drops_left_contribution() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let bytes = [0u8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        // Seed above with skip = 1 at (0, 0), BLOCK_4X4 ⇒ bw4 = bh4 = 1.
        walker
            .decode_skip(&mut dec, &mut cdfs, 0, 0, BLOCK_4X4, true)
            .unwrap();
        assert_eq!(walker.skips()[0], 1);

        // Rig CDFs so ctx = 1 reads as 0; ctx in {0, 2} reads as 1.
        cdfs.skip[0] = force_binary_cdf(1);
        cdfs.skip[1] = force_binary_cdf(0);
        cdfs.skip[2] = force_binary_cdf(1);
        // Block at (1, 0): above = (0, 0) ⇒ Skips[0][0] = 1. left at
        // (1, -1) is outside ⇒ AvailL = false. ctx = 1.
        let skip = walker
            .decode_skip(&mut dec, &mut cdfs, 1, 0, BLOCK_4X4, false)
            .unwrap();
        assert_eq!(skip, 0, "ctx = 1 selected (skip_cdf[1] forces 0)");
    }

    /// §8.3.2 skip-ctx walk respects non-zero tile origin: a block at
    /// the tile's top-left corner has `AvailU = AvailL = false` even
    /// though the global mi-grid neighbour cells exist. Place the
    /// block at the start of a tile whose `mi_row_start = mi_col_start
    /// = 8`. The walker's `is_inside((7, 8))` and `is_inside((8, 7))`
    /// both return false ⇒ ctx = 0.
    #[test]
    fn decode_skip_tile_origin_clears_avail() {
        let geom = TileGeometry {
            mi_row_start: 8,
            mi_row_end: 24,
            mi_col_start: 8,
            mi_col_end: 24,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        // Seed the global-grid neighbour at (7, 8) and (8, 7) so a
        // mistaken "use the global mi grid" implementation would
        // observe skip = 1 there.
        let bytes = [0u8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        walker
            .decode_skip(&mut dec, &mut cdfs, 7, 8, BLOCK_4X4, true)
            .unwrap();
        walker
            .decode_skip(&mut dec, &mut cdfs, 8, 7, BLOCK_4X4, true)
            .unwrap();

        cdfs.skip[0] = force_binary_cdf(0);
        cdfs.skip[1] = force_binary_cdf(1);
        cdfs.skip[2] = force_binary_cdf(1);
        let skip = walker
            .decode_skip(&mut dec, &mut cdfs, 8, 8, BLOCK_4X4, false)
            .unwrap();
        assert_eq!(
            skip, 0,
            "tile origin ⇒ AvailU = AvailL = false ⇒ ctx = 0, picks skip_cdf[0]"
        );
    }

    /// §5.11.5 grid-fill clipping: a leaf straddling the right edge of
    /// the frame fills only the in-grid portion of its `bw4`
    /// footprint. BLOCK_16X16 (bw4 = bh4 = 4) at (0, 30) on a 32-col
    /// frame: only cols 30 and 31 are filled.
    #[test]
    fn decode_skip_grid_fill_clips_right_edge() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let bytes = [0u8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        walker
            .decode_skip(&mut dec, &mut cdfs, 0, 30, BLOCK_16X16, true)
            .unwrap();
        // Cols 30, 31 of rows 0..4 are filled.
        for r in 0..4 {
            assert_eq!(walker.skips()[r * 32 + 30], 1);
            assert_eq!(walker.skips()[r * 32 + 31], 1);
        }
    }

    /// Out-of-range guards: `mi_row >= MiRows`, `mi_col >= MiCols`,
    /// `sub_size >= BLOCK_SIZES` all surface
    /// `Error::PartitionWalkOutOfRange`.
    #[test]
    fn decode_skip_rejects_out_of_range() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 8,
            mi_col_start: 0,
            mi_col_end: 8,
        };
        let mut walker = PartitionWalker::new(8, 8, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let bytes = [0u8; 4];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 4, true).unwrap();
        assert_eq!(
            walker.decode_skip(&mut dec, &mut cdfs, 8, 0, BLOCK_4X4, true),
            Err(crate::Error::PartitionWalkOutOfRange)
        );
        assert_eq!(
            walker.decode_skip(&mut dec, &mut cdfs, 0, 8, BLOCK_4X4, true),
            Err(crate::Error::PartitionWalkOutOfRange)
        );
        assert_eq!(
            walker.decode_skip(&mut dec, &mut cdfs, 0, 0, BLOCK_SIZES, true),
            Err(crate::Error::PartitionWalkOutOfRange)
        );
    }

    /// §5.11.5 grid-fill initial state: a fresh PartitionWalker has
    /// every `Skips[]` cell at 0 (the §9.4 default before any block is
    /// decoded).
    #[test]
    fn fresh_walker_skips_grid_is_zero() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 16,
            mi_col_start: 0,
            mi_col_end: 16,
        };
        let walker = PartitionWalker::new(16, 16, geom).unwrap();
        assert_eq!(walker.skips().len(), 16 * 16);
        assert!(walker.skips().iter().all(|&v| v == 0));
    }

    // Round 154 — §5.11.10 read_skip_mode walker tests.

    /// Helper: force a 2-symbol skip_mode CDF row (length 3) to select
    /// `symbol` on the next `read_symbol`. Mirrors `force_binary_cdf`
    /// (the §9.4 `DEFAULT_SKIP_MODE_CDF` rows are also `[a, 1 << 15,
    /// 0]`-shaped 2-symbol CDFs).
    fn force_skip_mode_cdf(symbol: u8) -> [u16; 3] {
        match symbol {
            0 => [1 << 15, 1 << 15, 0],
            1 => [0, 1 << 15, 0],
            _ => panic!("force_skip_mode_cdf supports 0 or 1 only"),
        }
    }

    /// §5.11.10 short-circuit set (case 1: seg short-circuit):
    /// `seg_feature_active(SEG_LVL_SKIP / REF_FRAME / GLOBALMV)` any
    /// true ⇒ `skip_mode = 0`, no symbol read. The decoder position
    /// must not advance.
    #[test]
    fn decode_skip_mode_seg_short_circuit_no_symbol_read() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let bytes = [0xFFu8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        let pos_before = dec.position();
        let skip_mode = walker
            .decode_skip_mode(&mut dec, &mut cdfs, 0, 0, BLOCK_16X16, true, true)
            .unwrap();
        assert_eq!(skip_mode, 0, "seg_skip_mode_off ⇒ skip_mode = 0");
        assert_eq!(
            dec.position(),
            pos_before,
            "no symbol bit read on the seg short-circuit"
        );
    }

    /// §5.11.10 short-circuit set (case 2: !skip_mode_present): the
    /// frame-header scalar from §5.9.21 is off ⇒ `skip_mode = 0`, no
    /// symbol read.
    #[test]
    fn decode_skip_mode_present_false_short_circuit() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let bytes = [0xFFu8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        let pos_before = dec.position();
        let skip_mode = walker
            .decode_skip_mode(&mut dec, &mut cdfs, 0, 0, BLOCK_16X16, false, false)
            .unwrap();
        assert_eq!(skip_mode, 0);
        assert_eq!(dec.position(), pos_before);
    }

    /// §5.11.10 short-circuit set (case 3a: Block_Width < 8): a
