        assert_eq!(walker.current_delta_lf(), &[0; FRAME_LF_COUNT]);
        // Apply a small +1 single-LF update.
        let mut cdfs = TileCdfContext::new_from_defaults();
        cdfs.delta_lf = force_delta_lf_cdf(1);
        let bytes = [0u8; 8];
