    /// §5.11.23 isCompound derivation: the §5.11.25 skip_mode arm with
    /// SkipModeFrame = [LAST, NONE] produces RefFrame[1] = NONE ⇒
    /// isCompound = false. With SkipModeFrame = [LAST, ALTREF] →
    /// RefFrame[1] = ALTREF > INTRA_FRAME ⇒ isCompound = true.
    /// (Verified indirectly via the walker grid stamp; the
    /// `DecodedInterBlockModeInfo` aggregate itself is gated behind
    /// the `Ok` arm which doesn't return on r170.)
    #[test]
    fn decoded_inter_block_mode_info_struct_public_api_smoke() {
        let info = DecodedInterBlockModeInfo {
            mi_row: 0,
            mi_col: 0,
            mi_size: BLOCK_4X4,
            ref_frame: [1, 7],
            is_compound: true,
            y_mode: MODE_NEAREST_NEARESTMV,
            ref_mv_idx: 0,
            num_mv_found: 0,
            new_mv_context: 0,
            ref_mv_context: 0,
            zero_mv_context: 0,
            mv: [[0, 0], [0, 0]],
            motion_mode: MOTION_MODE_SIMPLE,
            num_warp_samples: 0,
            interintra: InterIntraReadout {
                interintra: 0,
                interintra_mode: None,
                wedge_interintra: None,
                wedge_index: None,
            },
            compound_type: CompoundTypeReadout {
                comp_group_idx: 0,
                compound_idx: 1,
                compound_type: COMPOUND_AVERAGE,
                wedge_index: None,
                wedge_sign: None,
                mask_type: None,
            },
            interp_filter: InterpolationFilterReadout {
                interp_filter: [EIGHTTAP, EIGHTTAP],
                read_from_bitstream: [false, false],
            },
        };
        assert_eq!(info.ref_frame[0], 1);
        assert_eq!(info.ref_frame[1], 7);
        assert!(info.is_compound);
        assert_eq!(info.y_mode, MODE_NEAREST_NEARESTMV);
        assert_eq!(info.mv, [[0, 0], [0, 0]]);
        assert_eq!(info.motion_mode, MOTION_MODE_SIMPLE);
        assert_eq!(info.num_warp_samples, 0);
        assert_eq!(info.interintra.interintra, 0);
        // Single-pred case.
        let info_single = DecodedInterBlockModeInfo {
            mi_row: 0,
            mi_col: 0,
            mi_size: BLOCK_4X4,
            ref_frame: [1, -1],
            is_compound: false,
            y_mode: MODE_NEARESTMV,
            ref_mv_idx: 0,
            num_mv_found: 0,
            new_mv_context: 0,
            ref_mv_context: 0,
            zero_mv_context: 0,
            mv: [[12, -8], [0, 0]],
            motion_mode: MOTION_MODE_SIMPLE,
            num_warp_samples: 0,
            interintra: InterIntraReadout {
                interintra: 1,
                interintra_mode: Some(II_DC_PRED),
                wedge_interintra: Some(0),
                wedge_index: None,
            },
            compound_type: CompoundTypeReadout {
                comp_group_idx: 0,
                compound_idx: 1,
                compound_type: COMPOUND_INTRA,
                wedge_index: None,
                wedge_sign: None,
                mask_type: None,
            },
            interp_filter: InterpolationFilterReadout {
                interp_filter: [EIGHTTAP_SMOOTH, EIGHTTAP_SHARP],
                read_from_bitstream: [true, true],
            },
        };
        assert!(!info_single.is_compound);
        assert_eq!(info_single.y_mode, MODE_NEARESTMV);
        assert_eq!(info_single.mv[0], [12, -8]);
        // Slot 1 stays at the §5.11.5 pre-fill on single-pred.
        assert_eq!(info_single.mv[1], [0, 0]);
        assert_eq!(info_single.interintra.interintra, 1);
        assert_eq!(info_single.interintra.interintra_mode, Some(II_DC_PRED));
        assert_eq!(info_single.interintra.wedge_interintra, Some(0));
        assert_eq!(info_single.interintra.wedge_index, None);
    }

    /// §5.11.18 prologue + §5.11.23 grid composition: stamp
    /// `RefFrames[0][0..2][..]` via a first §5.11.23 call, then verify
    /// the next §5.11.18 prologue at `(0, 2)` reads the stamped values
    /// through `ref_frame_at` (the §8.3.2 ref-frame ctx walks rely on
    /// this propagation).
    #[test]
    fn ref_frames_grid_propagates_to_subsequent_neighbour_lookup() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 8,
            mi_col_start: 0,
            mi_col_end: 8,
        };
        let walker = PartitionWalker::new(8, 8, geom).unwrap();
        // Pre-fill identity: every cell starts at [INTRA_FRAME, NONE].
        assert_eq!(walker.ref_frame_at(0, 0, 0), 0);
        assert_eq!(walker.ref_frame_at(0, 0, 1), -1);
        // Out-of-grid coordinates return the spec's unavailable
        // fallback.
        assert_eq!(walker.ref_frame_at(-1, 0, 0), 0);
        assert_eq!(walker.ref_frame_at(-1, 0, 1), -1);
        assert_eq!(walker.ref_frame_at(0, 100, 0), 0);
        assert_eq!(walker.ref_frame_at(0, 100, 1), -1);
    }

    // ===================================================================
    // §5.11.23 post-find_mv_stack cascade tests (round 173)
    // ===================================================================

    /// §5.11.23 Arm 1 (`skip_mode == 1`): YMode = NEAREST_NEARESTMV
    /// (no `compound_mode` / `new_mv` / `zero_mv` / `ref_mv` S());
    /// `RefMvIdx = 0` and the drl_mode loops do NOT run because
    /// NEAREST_NEARESTMV is neither NEWMV/NEW_NEWMV nor has_nearmv.
    /// Position MUST equal `pos_before` (no bit was consumed past the
    /// §5.11.25 skip_mode arm, which itself reads 0 bits). Stack
    /// summary reflects spatial-only fresh-walker state
    /// (`num_mv_found = 0`, contexts = (0, 0, 0)).
    #[test]
    fn cascade_skip_mode_arm1_no_bits_consumed_y_mode_nearest_nearestmv() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 16,
            mi_col_start: 0,
            mi_col_end: 16,
        };
        let mut walker = PartitionWalker::new(16, 16, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let bytes = [0xFFu8; 32]; // hostile — Arm 1 must not touch it.
        let mut dec = SymbolDecoder::init_symbol(&bytes, 32, true).unwrap();
        let pos_before = dec.position();
        let mfmvs = MotionFieldMvs::new_invalid(walker.mi_rows(), walker.mi_cols());
        let r = walker.decode_inter_block_mode_info(
            &mut dec,
            &mut cdfs,
            4,
            4,
            BLOCK_8X8,
            /* skip_mode = */ 1,
            true,
            true,
            [0, -1],
            [0, -1],
            true,
            true,
            true,
            true,
            /* skip_mode_frame = */ [1, 7],
            false,
            0,
            false,
            false,
            true,
            [GM_TYPE_IDENTITY; 8],
            identity_gm_params(),
            [0; 8],
            false,
            false,
            false,
            /* is_motion_mode_switchable = */ false,
            /* allow_warped_motion = */ false,
            /* is_scaled_per_ref = */ [false; 7],
            /* enable_interintra_compound = */ false,
            /* enable_masked_compound = */ false,
            /* enable_jnt_comp = */ false,
            /* dist_equal = */ false,
            /* interpolation_filter = */ 0,
            /* enable_dual_filter = */ false,
            &mfmvs,
        );
        assert!(r.is_ok(), "r175: §5.11.27 read_motion_mode short-circuits to SIMPLE (no S()) on !is_motion_mode_switchable; the §5.11.23 dispatcher returns Ok(DecodedInterBlockModeInfo {{ motion_mode: SIMPLE, .. }}) — got {r:?}");
        assert_eq!(
            dec.position(),
            pos_before,
            "Arm 1 (skip_mode=1) ⇒ NEAREST_NEARESTMV reads no bits"
        );
    }

