    /// §5.11.31 NEWMV + `mv_joint = MV_JOINT_ZERO`: rig the §5.11.23
    /// Arm 4 single-pred cascade to YMode = NEWMV (`new_mv` ⇒ 0), then
    /// rig `mv_joint` ⇒ symbol 0 (MV_JOINT_ZERO). With diffMv = [0, 0]
    /// the final Mv = PredMv. Fresh walker on identity-GM has
    /// `RefStackMv[0][0] = [0, 0]`, so the stamped Mv is also [0, 0].
    ///
    /// Verifies that the §5.11.31 cascade consumed exactly the
    /// `new_mv` bit (the single-ref + zero/ref_mv arm reads don't fire
    /// because NEWMV is the first arm), the `mv_joint` bit, and ZERO
    /// `read_mv_component` calls — no `mv_sign` / `mv_class` reads.
    #[test]
    fn read_mv_newmv_with_mv_joint_zero_yields_zero_diff_mv() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 8,
            mi_col_start: 0,
            mi_col_end: 8,
        };
        let mut walker = PartitionWalker::new(8, 8, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        // Rig §5.11.23 Arm 4 single-pred for YMode = NEWMV.
        for row in cdfs.new_mv.iter_mut() {
            *row = force_binary_cdf(0);
        }
        // Single-ref deterministic — any conformant inter ref is fine.
        for row in cdfs.single_ref.iter_mut() {
            for slot in row.iter_mut() {
                *slot = force_binary_cdf(0);
            }
        }
        // §5.11.31 mv_joint ⇒ MV_JOINT_ZERO (symbol 0). 5-entry CDF
        // (MV_JOINTS + 1 = 5). For an all-zero bitstream
        // (SymbolValue ≈ range - 1) the §8.2.6 loop breaks at the first
        // index `s` where `cdf[s] = (1 << 15)` (which makes `cur`
        // tiny), so to force symbol 0 every CDF entry except the
        // counter is `(1 << 15)`.
        for row in cdfs.mv_joint.iter_mut() {
            *row = [1 << 15, 1 << 15, 1 << 15, 1 << 15, 0];
        }
        let bytes = [0u8; 32];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 32, true).unwrap();
        let mfmvs = MotionFieldMvs::new_invalid(walker.mi_rows(), walker.mi_cols());
        let r = walker.decode_inter_block_mode_info(
            &mut dec,
            &mut cdfs,
            0,
            0,
            BLOCK_4X4,
            0,
            false,
            false,
            [0, -1],
            [0, -1],
            true,
            true,
            true,
            true,
            [0, -1],
            false,
            0,
            false,
            false,
            /* reference_select = */ false,
            [GM_TYPE_IDENTITY; 8],
            identity_gm_params(),
            [0; 8],
            false,
            false,
            false,
            /* is_motion_mode_switchable = */ false,
            /* allow_warped_motion = */ false,
            /* is_scaled_per_ref = */ [false; 7],
            /* enable_interintra_compound = */ false,
            /* enable_masked_compound = */ false,
            /* enable_jnt_comp = */ false,
            /* dist_equal = */ false,
            /* interpolation_filter = */ 0,
            /* enable_dual_filter = */ false,
            &mfmvs,
        );
        assert!(r.is_ok(), "r175: §5.11.27 read_motion_mode short-circuits to SIMPLE (no S()) on !is_motion_mode_switchable; the §5.11.23 dispatcher returns Ok(DecodedInterBlockModeInfo {{ motion_mode: SIMPLE, .. }}) — got {r:?}");
        // Mvs grid: identity-GM PredMv = [0, 0], MV_JOINT_ZERO diff =
        // [0, 0], so final Mv[0] = [0, 0].
        assert_eq!(walker.mvs()[0], 0);
        assert_eq!(walker.mvs()[1], 0);
        // mv_sign / mv_class CDF counters MUST stay 0 (no read fired).
        for row in &cdfs.mv_sign {
            for slot in row {
                assert_eq!(
                    slot[2], 0,
                    "mv_sign CDF must not have adapted on MV_JOINT_ZERO"
                );
            }
        }
        for row in &cdfs.mv_class {
            for slot in row {
                assert_eq!(
                    slot[11], 0,
                    "mv_class CDF must not have adapted on MV_JOINT_ZERO"
                );
            }
        }
    }

    /// §5.11.31 cascade structural smoke: when the §5.11.23 dispatch
    /// reaches the inter cascade and the §5.11.31 assign_mv body
    /// fires, the resulting Mv values are constrained by the
    /// §6.10.25 conformance bound (`|Mv[i][c]| < (1 << 14)`). The
    /// per-arc rigs above (NEWMV cascade with `mv_joint = MV_JOINT_ZERO`
    /// plus identity GM) exercise the zero-diff path; this test
    /// verifies the larger-diff path stays within the bound after a
    /// full rigged cascade. Symbol-by-symbol assertions on the rigged
    /// CDFs are not robust because the AV1 arithmetic coder is
    /// stateful; instead we assert structural invariants.
    #[test]
    fn cascade_assign_mv_produces_in_range_mv_values() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 8,
            mi_col_start: 0,
            mi_col_end: 8,
        };
        let mut walker = PartitionWalker::new(8, 8, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        // YMode = NEWMV ⇒ assign_mv invokes read_mv ⇒ read_mv_component.
        for row in cdfs.new_mv.iter_mut() {
            *row = force_binary_cdf(0);
        }
        for row in cdfs.single_ref.iter_mut() {
            for slot in row.iter_mut() {
                *slot = force_binary_cdf(0);
            }
        }
        let bytes = [0u8; 32];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 32, true).unwrap();
        let mfmvs = MotionFieldMvs::new_invalid(walker.mi_rows(), walker.mi_cols());
        let r = walker.decode_inter_block_mode_info(
            &mut dec,
            &mut cdfs,
            0,
            0,
            BLOCK_4X4,
            0,
            false,
            false,
            [0, -1],
            [0, -1],
            true,
            true,
            true,
            true,
            [0, -1],
            false,
            0,
            false,
            false,
            false,
            [GM_TYPE_IDENTITY; 8],
            identity_gm_params(),
            [0; 8],
            false,
            false,
            false,
            /* is_motion_mode_switchable = */ false,
            /* allow_warped_motion = */ false,
            /* is_scaled_per_ref = */ [false; 7],
            /* enable_interintra_compound = */ false,
            /* enable_masked_compound = */ false,
            /* enable_jnt_comp = */ false,
            /* dist_equal = */ false,
            /* interpolation_filter = */ 0,
            /* enable_dual_filter = */ false,
            &mfmvs,
        );
        assert!(r.is_ok(), "r175: §5.11.27 read_motion_mode short-circuits to SIMPLE (no S()) on !is_motion_mode_switchable; the §5.11.23 dispatcher returns Ok(DecodedInterBlockModeInfo {{ motion_mode: SIMPLE, .. }}) — got {r:?}");
        // §6.10.25 `is_mv_valid`: |Mv[i][c]| < (1 << 14) = 16384.
        for list in 0..2 {
            for comp in 0..2 {
                let v = walker.mvs()[((list) * 2) * 2 + comp].unsigned_abs() as i32;
                assert!(
                    v < (1 << 14),
                    "|Mv[{list}][{comp}]| = {v} must be < (1 << 14)"
                );
            }
        }
    }

    /// §5.11.32 `read_mv_component` direct exercise — all five reads
    /// rigged to symbol 0 (sign=0, class=0, class0_bit=0,
    /// class0_fr=0, class0_hp=0 when allow_hp=true). The §8.2.6 cdf
    /// rig `[1 << 15; CDF_LEN - 1] + [0]` (built by [`force_cdf`])
    /// puts `cur = 4 * (N - 1)` at `s = 0` which is always <= the
    /// decoder's `value` (regardless of state), so symbol 0 is
    /// deterministic.
    ///
    /// With sign=0, class=0, class0_bit=0, class0_fr=0,
    /// allow_high_precision_mv=true ⇒ class0_hp read fires and = 0.
    /// mag = ((0 << 3) | (0 << 1) | 0) + 1 = 1.
    #[test]
    fn read_mv_component_direct_class0_all_zero_yields_mag_one() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 4,
            mi_col_start: 0,
            mi_col_end: 4,
        };
        let mut walker = PartitionWalker::new(4, 4, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        // Force every symbol read to 0.
        for row in cdfs.mv_sign.iter_mut() {
            for slot in row.iter_mut() {
                *slot = force_cdf::<3>(0);
            }
        }
        for row in cdfs.mv_class.iter_mut() {
            for slot in row.iter_mut() {
                *slot = force_cdf::<12>(0);
            }
        }
        for row in cdfs.mv_class0_bit.iter_mut() {
            for slot in row.iter_mut() {
                *slot = force_cdf::<3>(0);
            }
        }
        for row in cdfs.mv_class0_fr.iter_mut() {
            for slot in row.iter_mut() {
                for inner in slot.iter_mut() {
                    *inner = force_cdf::<5>(0);
                }
            }
        }
        for row in cdfs.mv_class0_hp.iter_mut() {
            for slot in row.iter_mut() {
                *slot = force_cdf::<3>(0);
            }
        }
        let bytes = [0u8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        let r = walker.read_mv_component(
            &mut dec, &mut cdfs, /* comp = */ 0, /* mv_ctx = */ 0,
            /* allow_high_precision_mv = */ true, /* force_integer_mv = */ false,
        );
        assert_eq!(r, Ok(1), "all-sym-0 class-0 ladder ⇒ mag = 0 + 1 = 1");
    }

    /// §5.11.32 `read_mv_component` direct exercise — same as the
    /// all-zero test but with `allow_high_precision_mv = false`. The
    /// `mv_class0_hp` read is skipped and the §5.11.32 fall-through
    /// `mv_class0_hp = 1` applies. mag = ((0<<3)|(0<<1)|1) + 1 = 2.
    #[test]
    fn read_mv_component_direct_class0_no_hp_yields_mag_two() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 4,
            mi_col_start: 0,
            mi_col_end: 4,
        };
        let mut walker = PartitionWalker::new(4, 4, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        for row in cdfs.mv_sign.iter_mut() {
            for slot in row.iter_mut() {
                *slot = force_cdf::<3>(0);
            }
        }
        for row in cdfs.mv_class.iter_mut() {
            for slot in row.iter_mut() {
                *slot = force_cdf::<12>(0);
            }
        }
        for row in cdfs.mv_class0_bit.iter_mut() {
            for slot in row.iter_mut() {
                *slot = force_cdf::<3>(0);
            }
        }
        for row in cdfs.mv_class0_fr.iter_mut() {
            for slot in row.iter_mut() {
                for inner in slot.iter_mut() {
                    *inner = force_cdf::<5>(0);
                }
            }
        }
        let bytes = [0u8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        let r = walker.read_mv_component(
            &mut dec, &mut cdfs, 0, 0, /* allow_high_precision_mv = */ false,
            /* force_integer_mv = */ false,
        );
        assert_eq!(
            r,
            Ok(2),
            "fall-through hp=1 ⇒ mag = ((0<<3)|(0<<1)|1)+1 = 2"
        );
    }

    /// §5.11.32 `read_mv_component` — `mv_sign = 1` negates the
    /// magnitude. Same setup as the all-zero class-0 test but with
    /// `mv_sign` rigged to symbol 1 via `[1, 1<<15, 0]` (which forces
    /// sym 1 on the first read off a fresh decoder: value=32767,
    /// cur(s=0) = ((128*511)>>1)+4*1 = 32704+4 = 32708, value >= cur
    /// → wait, value=32767 ≥ 32708 ⇒ break, sym=0). For reliable
    /// sym=1 on the FIRST read we need cur(s=0) > value(32767).
    /// `cdf[0]=0` ⇒ cur = (128*512)>>1 + 4 = 32768+4 = 32772 > 32767
    /// ⇒ continue. Then cdf[1]=(1<<15) ⇒ cur tiny ⇒ break with sym=1.
    /// This pattern is deterministic ONLY for the first read off a
    /// fresh decoder. (Subsequent reads' `value`/`range` evolve and
    /// the cdf[0]=0 trick may then under-cur.)
    #[test]
    fn read_mv_component_direct_with_sign_negates_mag() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 4,
            mi_col_start: 0,
            mi_col_end: 4,
        };
        let mut walker = PartitionWalker::new(4, 4, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        // mv_sign is the FIRST read; rig to symbol 1 via the
        // fresh-state-only `[0, 1<<15, 0]` pattern (matches
        // `force_binary_cdf(1)`).
        for row in cdfs.mv_sign.iter_mut() {
            for slot in row.iter_mut() {
                *slot = [0, 1 << 15, 0];
            }
        }
        // After the first read (mv_sign), subsequent rig back to
        // robust sym-0.
        for row in cdfs.mv_class.iter_mut() {
            for slot in row.iter_mut() {
                *slot = force_cdf::<12>(0);
            }
        }
        for row in cdfs.mv_class0_bit.iter_mut() {
            for slot in row.iter_mut() {
                *slot = force_cdf::<3>(0);
            }
        }
        for row in cdfs.mv_class0_fr.iter_mut() {
            for slot in row.iter_mut() {
                for inner in slot.iter_mut() {
                    *inner = force_cdf::<5>(0);
                }
            }
        }
        let bytes = [0u8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        let r = walker.read_mv_component(
            &mut dec, &mut cdfs, 0, 0, /* allow_high_precision_mv = */ false,
            /* force_integer_mv = */ false,
        );
        // mag = 2 (as above), sign = 1 ⇒ -2.
        assert_eq!(r, Ok(-2), "mv_sign = 1 negates mag = 2 to -2");
    }

    /// §5.11.32 `read_mv_component` — `force_integer_mv = true`
    /// short-circuits the `mv_class0_fr` read (forces value = 3) and
    /// also the `mv_fr` read for class > 0. Combined with all other
    /// reads forced to sym 0 (sign=0, class=0, class0_bit=0,
    /// allow_high_precision_mv=false → class0_hp fall-through=1):
    /// mag = ((0 << 3) | (3 << 1) | 1) + 1 = 7 + 1 = 8.
    #[test]
    fn read_mv_component_direct_force_integer_uses_fr_three() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 4,
            mi_col_start: 0,
            mi_col_end: 4,
        };
        let mut walker = PartitionWalker::new(4, 4, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        for row in cdfs.mv_sign.iter_mut() {
            for slot in row.iter_mut() {
                *slot = force_cdf::<3>(0);
            }
        }
        for row in cdfs.mv_class.iter_mut() {
            for slot in row.iter_mut() {
                *slot = force_cdf::<12>(0);
            }
        }
        for row in cdfs.mv_class0_bit.iter_mut() {
            for slot in row.iter_mut() {
                *slot = force_cdf::<3>(0);
            }
        }
        // mv_class0_fr is rigged to symbol 0 to verify the §5.11.32
        // `force_integer_mv = 1` path SKIPS the read entirely (so the
        // rig is irrelevant — fr is always 3 on this path).
        for row in cdfs.mv_class0_fr.iter_mut() {
            for slot in row.iter_mut() {
                for inner in slot.iter_mut() {
                    *inner = force_cdf::<5>(0);
                }
            }
        }
        let bytes = [0u8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        let r = walker.read_mv_component(
            &mut dec, &mut cdfs, 0, 0, /* allow_high_precision_mv = */ false,
            /* force_integer_mv = */ true,
        );
        assert_eq!(
            r,
            Ok(8),
            "force_integer_mv ⇒ fr=3 ⇒ mag = ((0<<3)|(3<<1)|1)+1 = 8"
        );
    }

    /// §5.11.31 assign_mv defensive guard: passing `use_intrabc =
    /// true` through the internal helper surfaces
    /// `PartitionWalkOutOfRange`. The inter dispatcher hard-codes
    /// `use_intrabc = false`; this test directly exercises the guard.
    #[test]
    fn assign_mv_rejects_use_intrabc_in_inter_arm() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 8,
            mi_col_start: 0,
            mi_col_end: 8,
        };
        let mut walker = PartitionWalker::new(8, 8, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let bytes = [0u8; 16];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 16, true).unwrap();
        let stack: [[[i32; 2]; 2]; MAX_REF_MV_STACK_SIZE] = [[[0, 0]; 2]; MAX_REF_MV_STACK_SIZE];
        let globals: [[i32; 2]; 2] = [[0, 0], [0, 0]];
        let r = walker.assign_mv(
            &mut dec,
            &mut cdfs,
            false,
            /* use_intrabc = */ true,
            MODE_NEARESTMV,
            0,
            0,
            &stack,
            &globals,
            false,
            false,
        );
        assert_eq!(r, Err(crate::Error::PartitionWalkOutOfRange));
    }

    /// Helper: build the per-ref identity global-motion matrices
    /// (`GmType[ref] = IDENTITY` for every ref). The §7.10.2.1
    /// short-circuit path returns `[0, 0]` for any ref under this
    /// configuration.
    fn identity_gm() -> ([i32; 8], [[i32; 6]; 8]) {
        let mut params = [[0i32; 6]; 8];
        // §5.9.24 identity default: gm_params[ref][2] = gm_params[ref][5]
        // = 1 << WARPEDMODEL_PREC_BITS; other slots = 0.
        for p in &mut params {
            p[2] = 1 << WARPEDMODEL_PREC_BITS;
            p[5] = 1 << WARPEDMODEL_PREC_BITS;
        }
        ([GM_TYPE_IDENTITY; 8], params)
    }

    /// Helper: a sign-bias array (§5.9.20) — all zero (every ref same
    /// direction). The §7.10.2.13 negation arm depends on this.
    fn zero_sign_bias() -> [i32; 8] {
        [0; 8]
    }

    /// §7.10.2.10 lower-precision contract: with `allow_high_precision_mv
    /// == true`, the MV passes through unchanged.
    #[test]
    fn lower_mv_precision_high_precision_passthrough() {
        let mv = lower_mv_precision([7, -5], true, false);
        assert_eq!(mv, [7, -5]);
        let mv2 = lower_mv_precision([7, -5], true, true);
        // §7.10.2.10 explicitly terminates on `allow_high_precision_mv
        // == 1` before checking force_integer_mv.
        assert_eq!(mv2, [7, -5]);
    }

    /// §7.10.2.10 with high_precision off: only the least significant
    /// bit is rounded toward zero.
    #[test]
    fn lower_mv_precision_strips_lsb_when_high_precision_off() {
        assert_eq!(lower_mv_precision([7, 5], false, false), [6, 4]);
        assert_eq!(lower_mv_precision([-7, -5], false, false), [-6, -4]);
        // Already-even values pass through.
        assert_eq!(lower_mv_precision([6, -4], false, false), [6, -4]);
        assert_eq!(lower_mv_precision([0, 0], false, false), [0, 0]);
    }

    /// §7.10.2.10 with `force_integer_mv == 1`: all three fractional
    /// bits are stripped — `(|a| + 3) >> 3 << 3`.
    #[test]
    fn lower_mv_precision_force_integer_strips_all_fractional() {
        // |11| = 11 → (11+3)>>3 = 1 → 1<<3 = 8
        assert_eq!(lower_mv_precision([11, -11], false, true), [8, -8]);
        // |0| = 0 → 0
        assert_eq!(lower_mv_precision([0, 0], false, true), [0, 0]);
        // |4| = 4 → (4+3)>>3 = 0 → 0
        assert_eq!(lower_mv_precision([4, -4], false, true), [0, 0]);
        // |12| = 12 → (12+3)>>3 = 1 → 8
        assert_eq!(lower_mv_precision([12, -12], false, true), [8, -8]);
        // |16| = 16 → (16+3)>>3 = 2 → 16
        assert_eq!(lower_mv_precision([16, -16], false, true), [16, -16]);
    }

    /// §5.11.53 clamp_mv_row: clamps to `mbToTopEdge - border` /
    /// `mbToBottomEdge + border`.
    #[test]
    fn clamp_mv_row_brackets_to_frame_with_border() {
        // 8×8 mi grid, bh4 = 1 (BLOCK_4X4), mi_row = 4.
        // mbToTopEdge = -(4 * 4 * 8) = -128.
        // mbToBottomEdge = ((8 - 1 - 4) * 4 * 8) = 96.
        // border = MV_BORDER (128) + 4 * 8 = 160 (for bh = 4).
        let row_border = MV_BORDER + 4 * 8;
        let mi_rows = 8;
        let bh4 = 1;
        let mi_row = 4;
        // In-range: 0 passes through.
        assert_eq!(clamp_mv_row(0, row_border, mi_rows, bh4, mi_row), 0);
        // Out-of-range top: clamps to mbToTopEdge - border = -128 - 160 = -288.
        assert_eq!(clamp_mv_row(-9999, row_border, mi_rows, bh4, mi_row), -288);
        // Out-of-range bottom: clamps to mbToBottomEdge + border = 96 + 160 = 256.
        assert_eq!(clamp_mv_row(9999, row_border, mi_rows, bh4, mi_row), 256);
    }

    /// §5.11.54 clamp_mv_col: same shape as clamp_mv_row but on the
    /// horizontal axis.
    #[test]
    fn clamp_mv_col_brackets_to_frame_with_border() {
        let col_border = MV_BORDER + 4 * 8;
        let mi_cols = 8;
        let bw4 = 1;
        let mi_col = 4;
        assert_eq!(clamp_mv_col(0, col_border, mi_cols, bw4, mi_col), 0);
        assert_eq!(clamp_mv_col(-9999, col_border, mi_cols, bw4, mi_col), -288);
        assert_eq!(clamp_mv_col(9999, col_border, mi_cols, bw4, mi_col), 256);
    }

    /// §7.10.2.11 sorting: stable descending sort of WeightStack pulls
    /// the heaviest entry to the front. The companion RefStackMv rows
    /// swap in lockstep.
    #[test]
    fn sort_stack_segment_descends_by_weight() {
        let mut state = MvStackState::new();
        state.num_mv_found = 4;
        state.weight_stack[0] = 10;
        state.weight_stack[1] = 50;
        state.weight_stack[2] = 30;
        state.weight_stack[3] = 20;
        state.ref_stack_mv[0][0] = [100, 0];
        state.ref_stack_mv[1][0] = [200, 0];
        state.ref_stack_mv[2][0] = [300, 0];
        state.ref_stack_mv[3][0] = [400, 0];
        sort_stack_segment(&mut state, 0, 4, false);
        assert_eq!(state.weight_stack[0], 50);
        assert_eq!(state.weight_stack[1], 30);
        assert_eq!(state.weight_stack[2], 20);
        assert_eq!(state.weight_stack[3], 10);
        assert_eq!(state.ref_stack_mv[0][0], [200, 0]);
        assert_eq!(state.ref_stack_mv[1][0], [300, 0]);
        assert_eq!(state.ref_stack_mv[2][0], [400, 0]);
        assert_eq!(state.ref_stack_mv[3][0], [100, 0]);
    }

    /// §7.10.2.11 sort: equal weights preserve original order (stable).
    #[test]
    fn sort_stack_segment_is_stable_on_equal_weights() {
        let mut state = MvStackState::new();
        state.num_mv_found = 3;
        state.weight_stack[0] = 10;
        state.weight_stack[1] = 10;
        state.weight_stack[2] = 10;
        state.ref_stack_mv[0][0] = [1, 0];
        state.ref_stack_mv[1][0] = [2, 0];
        state.ref_stack_mv[2][0] = [3, 0];
        sort_stack_segment(&mut state, 0, 3, false);
        // Equal weights ⇒ no swaps; order preserved.
        assert_eq!(state.ref_stack_mv[0][0], [1, 0]);
        assert_eq!(state.ref_stack_mv[1][0], [2, 0]);
        assert_eq!(state.ref_stack_mv[2][0], [3, 0]);
    }

    /// §7.10.2.1 setup-global-mv on `INTRA_FRAME` (refList = 0
    /// pointing at the implicit intra ref ordinal): returns `[0, 0]`.
    #[test]
    fn setup_global_mv_intra_frame_is_zero() {
        let (gm_type, gm_params) = identity_gm();
        let mv = setup_global_mv(0, 0, BLOCK_8X8, 0, &gm_type, &gm_params, false, false);
        assert_eq!(mv, [0, 0]);
    }

    /// §7.10.2.1 setup-global-mv on `IDENTITY` (the §5.9.24
    /// `FrameIsIntra` default): returns `[0, 0]` regardless of which
    /// inter ref is selected.
    #[test]
    fn setup_global_mv_identity_is_zero_for_inter_refs() {
        let (gm_type, gm_params) = identity_gm();
        for ref_idx in 1..=7 {
            let mv = setup_global_mv(0, 0, BLOCK_8X8, ref_idx, &gm_type, &gm_params, false, false);
            assert_eq!(mv, [0, 0], "ref {ref_idx} with IDENTITY GmType");
        }
    }

    /// §7.10.2.1 setup-global-mv on `TRANSLATION`: returns
    /// `[gm_params[ref][0] >> (PREC - 3), gm_params[ref][1] >> (PREC - 3)]`.
    /// With high-precision off, the LSB is then stripped.
    #[test]
    fn setup_global_mv_translation_shifts_params() {
        let (mut gm_type, mut gm_params) = identity_gm();
        // LAST_FRAME = 1 with TRANSLATION; gm_params[1][0] = 8192 (= 1
        // << 13), gm_params[1][1] = -8192. WARPEDMODEL_PREC_BITS - 3 =
        // 13, so the shift produces ±1 raw → after high-precision-off
        // strip-LSB: 0. With high-precision-on: ±1.
        gm_type[1] = GM_TYPE_TRANSLATION;
        gm_params[1][0] = 1 << 13;
        gm_params[1][1] = -(1 << 13);
        let mv_hi = setup_global_mv(0, 0, BLOCK_8X8, 1, &gm_type, &gm_params, true, false);
        assert_eq!(mv_hi, [1, -1]);
        let mv_lo = setup_global_mv(0, 0, BLOCK_8X8, 1, &gm_type, &gm_params, false, false);
        // After lower-precision strip: 1 has LSB set → 1 → 0 (toward zero).
        assert_eq!(mv_lo, [0, 0]);
    }

    // ===================================================================
    // §7.10 find_mv_stack tests (round 172)
    // ===================================================================

    /// §7.10 driver on an empty walker (no inter neighbours), single
    /// prediction with IDENTITY global motion. Expected outcome:
    /// `NumMvFound == 0`, `NewMvCount == 0`, all global MVs zero,
    /// CloseMatches / TotalMatches == 0, NewMvContext == 0,
    /// RefMvContext == 0.
    #[test]
    fn find_mv_stack_empty_walker_single_pred_identity_gm() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 16,
            mi_col_start: 0,
            mi_col_end: 16,
        };
        let walker = PartitionWalker::new(16, 16, geom).unwrap();
        let (gm_type, gm_params) = identity_gm();
        let mfmvs = MotionFieldMvs::new_invalid(walker.mi_rows(), walker.mi_cols());
        let res = walker
            .find_mv_stack(
                4,
                4,
                BLOCK_8X8,
                [1, -1], // LAST_FRAME, NONE — single pred
                false,
                false, // use_ref_frame_mvs
                gm_type,
                gm_params,
                zero_sign_bias(),
                false,
                false,
                &mfmvs,
            )
            .unwrap();
        assert_eq!(res.num_mv_found, 0, "no inter neighbours ⇒ stack empty");
        assert_eq!(res.new_mv_count, 0);
        assert_eq!(res.close_matches, 0);
        assert_eq!(res.total_matches, 0);
        assert_eq!(res.num_nearest, 0);
        assert_eq!(res.num_new, 0);
        assert_eq!(res.zero_mv_context, 0);
        assert_eq!(res.new_mv_context, 0);
        assert_eq!(res.ref_mv_context, 0);
        assert_eq!(res.global_mvs[0], [0, 0]);
    }

    /// §7.10 driver on an empty walker, compound prediction with
    /// IDENTITY global motion. The §7.10.2.12 extra-search compound
    /// fill emits two global MVs into the stack: `NumMvFound == 2`,
    /// every slot zero, weight 2.
    #[test]
    fn find_mv_stack_empty_walker_compound_identity_gm_fills_two() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 16,
            mi_col_start: 0,
            mi_col_end: 16,
        };
        let walker = PartitionWalker::new(16, 16, geom).unwrap();
        let (gm_type, gm_params) = identity_gm();
        let mfmvs = MotionFieldMvs::new_invalid(walker.mi_rows(), walker.mi_cols());
        let res = walker
            .find_mv_stack(
                4,
                4,
                BLOCK_8X8,
                [1, 7], // LAST_FRAME, ALTREF_FRAME — compound
                true,
                false,
                gm_type,
                gm_params,
                zero_sign_bias(),
                false,
                false,
                &mfmvs,
            )
            .unwrap();
        // §7.10.2.12 compound: NumMvFound was 0 ⇒ extra-search emits
        // both combinedMvs slots, each populated with GlobalMvs
        // because RefIdMvs/RefDiffMvs are both empty.
        assert_eq!(res.num_mv_found, 2);
        assert_eq!(res.ref_stack_mv[0][0], [0, 0]);
        assert_eq!(res.ref_stack_mv[0][1], [0, 0]);
        assert_eq!(res.ref_stack_mv[1][0], [0, 0]);
        assert_eq!(res.ref_stack_mv[1][1], [0, 0]);
        assert_eq!(res.weight_stack[0], 2);
        assert_eq!(res.weight_stack[1], 2);
        // CloseMatches still 0 — no spatial neighbours were inter.
        assert_eq!(res.close_matches, 0);
        assert_eq!(res.num_nearest, 0);
    }

    /// §7.10 driver caller-bug guards.
    #[test]
    fn find_mv_stack_caller_bug_guards() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 8,
            mi_col_start: 0,
            mi_col_end: 8,
        };
        let walker = PartitionWalker::new(8, 8, geom).unwrap();
        let (gm_type, gm_params) = identity_gm();
        let mfmvs = MotionFieldMvs::new_invalid(walker.mi_rows(), walker.mi_cols());

        // sub_size >= BLOCK_SIZES
        assert!(matches!(
            walker.find_mv_stack(
                0,
                0,
                BLOCK_SIZES,
                [1, -1],
                false,
                false,
                gm_type,
                gm_params,
                zero_sign_bias(),
                false,
                false,
                &mfmvs,
            ),
            Err(crate::Error::PartitionWalkOutOfRange)
        ));
        // mi_row out of grid
        assert!(matches!(
            walker.find_mv_stack(
                99,
                0,
                BLOCK_4X4,
                [1, -1],
                false,
                false,
                gm_type,
                gm_params,
                zero_sign_bias(),
                false,
                false,
                &mfmvs,
            ),
            Err(crate::Error::PartitionWalkOutOfRange)
        ));
        // ref_frame[0] out of range
        assert!(matches!(
            walker.find_mv_stack(
                0,
                0,
                BLOCK_4X4,
                [-1, -1],
                false,
                false,
                gm_type,
                gm_params,
                zero_sign_bias(),
                false,
                false,
                &mfmvs,
            ),
            Err(crate::Error::PartitionWalkOutOfRange)
        ));
        // ref_frame[1] out of range
        assert!(matches!(
            walker.find_mv_stack(
                0,
                0,
                BLOCK_4X4,
                [1, 9],
                true,
                false,
                gm_type,
                gm_params,
                zero_sign_bias(),
                false,
                false,
                &mfmvs,
            ),
            Err(crate::Error::PartitionWalkOutOfRange)
        ));
        // is_compound mismatch (claims compound but ref_frame[1] = NONE)
        assert!(matches!(
            walker.find_mv_stack(
                0,
                0,
                BLOCK_4X4,
                [1, -1],
                true,
                false,
                gm_type,
                gm_params,
                zero_sign_bias(),
                false,
                false,
                &mfmvs,
            ),
            Err(crate::Error::PartitionWalkOutOfRange)
        ));
    }

    /// §7.10 r205 temporal-scan opt-in with an all-sentinel
    /// motion-field grid runs to completion. The §7.10.2.6
    /// `candMv[0] == MFMV_INVALID` early-return fires at every
    /// position, so num_mv_found / weight_stack / ref_stack_mv are
    /// not perturbed. The only observable side effect is the
    /// §7.10.2.6 centre-cell ZeroMvContext stamp (`deltaRow == 0
    /// && deltaCol == 0` ⇒ `ZeroMvContext = 1`), which the spec
    /// sets BEFORE the invalid-sentinel return.
    #[test]
    fn find_mv_stack_temporal_scan_invalid_grid_only_stamps_zero_mv_context() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 8,
            mi_col_start: 0,
            mi_col_end: 8,
        };
        let walker = PartitionWalker::new(8, 8, geom).unwrap();
        let (gm_type, gm_params) = identity_gm();
        let mfmvs = MotionFieldMvs::new_invalid(walker.mi_rows(), walker.mi_cols());
        let r_opt_in = walker
            .find_mv_stack(
                0,
                0,
                BLOCK_4X4,
                [1, -1],
                false,
                true, // use_ref_frame_mvs
                gm_type,
                gm_params,
                zero_sign_bias(),
                false,
                false,
                &mfmvs,
            )
            .expect("invalid-grid opt-in runs to completion");
        let r_opt_out = walker
            .find_mv_stack(
                0,
                0,
                BLOCK_4X4,
                [1, -1],
                false,
                false,
                gm_type,
                gm_params,
                zero_sign_bias(),
                false,
                false,
                &mfmvs,
            )
            .expect("opt-out path runs to completion");
        // Stack contents identical: no candidate landed.
        assert_eq!(r_opt_in.num_mv_found, r_opt_out.num_mv_found);
        assert_eq!(r_opt_in.new_mv_count, r_opt_out.new_mv_count);
        assert_eq!(r_opt_in.ref_stack_mv, r_opt_out.ref_stack_mv);
        assert_eq!(r_opt_in.weight_stack, r_opt_out.weight_stack);
        assert_eq!(r_opt_in.global_mvs, r_opt_out.global_mvs);
        assert_eq!(r_opt_in.new_mv_context, r_opt_out.new_mv_context);
        assert_eq!(r_opt_in.ref_mv_context, r_opt_out.ref_mv_context);
        // §7.10.2.6 centre-cell stamp on the opt-in path:
        // ZeroMvContext = 1.
        assert_eq!(r_opt_in.zero_mv_context, 1);
        // Opt-out path leaves the §7.10.2 step-16 default of 0.
        assert_eq!(r_opt_out.zero_mv_context, 0);
    }

    /// r205 §7.9.1 motion-field grid initialisation:
    /// `MotionFieldMvs::new_invalid` sizes the grid to `(mi_rows >> 1)
    /// × (mi_cols >> 1)` per the §7.9.1 setup and fills every cell
    /// with the `MFMV_INVALID = -32768` sentinel.
    #[test]
    fn motion_field_mvs_new_invalid_sizes_and_sentinels() {
        let grid = MotionFieldMvs::new_invalid(16, 8);
        assert_eq!(grid.h8(), 8);
        assert_eq!(grid.w8(), 4);
        for ref_frame in 1..=7 {
            for y in 0..grid.h8() {
                for x in 0..grid.w8() {
                    assert_eq!(grid.get(ref_frame, y, x), [MFMV_INVALID, MFMV_INVALID]);
                }
            }
        }
    }

    /// r205 §7.9.2 motion-field stamp: `set` overwrites both
    /// components; `get` returns the stamped value. Out-of-grid
    /// reads return the sentinel.
    #[test]
    fn motion_field_mvs_set_get_round_trip_and_out_of_grid_sentinel() {
        let mut grid = MotionFieldMvs::new_invalid(8, 8);
        grid.set(/* LAST_FRAME = */ 1, 2, 3, [123, -456]);
        assert_eq!(grid.get(1, 2, 3), [123, -456]);
        // Other refs at (2, 3) unchanged.
        assert_eq!(grid.get(2, 2, 3), [MFMV_INVALID, MFMV_INVALID]);
        // Out-of-grid reads return the sentinel (the §7.10.2.6
        // outer is_inside check is the caller's responsibility, but
        // out-of-grid still doesn't panic).
        assert_eq!(grid.get(1, 100, 0), [MFMV_INVALID, MFMV_INVALID]);
        assert_eq!(grid.get(1, 0, 100), [MFMV_INVALID, MFMV_INVALID]);
        // INTRA_FRAME (= 0) and out-of-range refs sentinel out.
        assert_eq!(grid.get(0, 0, 0), [MFMV_INVALID, MFMV_INVALID]);
        assert_eq!(grid.get(8, 0, 0), [MFMV_INVALID, MFMV_INVALID]);
    }

    /// r205 §7.9.2 `set_all_refs` stamps every reference frame at
    /// the same `(y8, x8)` with the same MV — the §7.9.2 inner-loop
    /// shape (`for dst = LAST_FRAME; dst <= ALTREF_FRAME; dst++`).
    #[test]
    fn motion_field_mvs_set_all_refs_stamps_every_ref() {
        let mut grid = MotionFieldMvs::new_invalid(8, 8);
        grid.set_all_refs(1, 2, [99, 100]);
        for ref_frame in 1..=7 {
            assert_eq!(grid.get(ref_frame, 1, 2), [99, 100]);
        }
    }

    /// r205 §7.9.3 `get_mv_projection`: numerator == denominator
    /// returns the source MV unchanged (modulo clamping). The
    /// `Div_Mult[denom]` table is the round-to-nearest inverse:
    /// `round(2^14 / denom)`. With numerator == denominator the
    /// product `numerator * Div_Mult[denom]` ≈ 2^14, and the
    /// `Round2Signed(mv * 2^14, 14)` recovers the input.
    #[test]
    fn get_mv_projection_identity_when_num_eq_denom() {
        // numerator == denominator == 4: Div_Mult[4] = 4096 = 2^12.
        // mv * 4 * 4096 = mv * 2^14 → Round2Signed(_, 14) = mv.
        let mv = get_mv_projection([100, -100], 4, 4);
        assert_eq!(mv, [100, -100]);
        // denominator == 1 ⇒ Div_Mult[1] = 16384 = 2^14 → mv * 1 *
        // 2^14, Round2Signed(_, 14) = mv.
        let mv = get_mv_projection([42, 17], 1, 1);
        assert_eq!(mv, [42, 17]);
    }

    /// r205 §7.9.3 clamp: projected components saturate at
    /// `±((1 << MV_IN_USE_BITS) - 1)`. A large source MV scaled with
    /// numerator > denominator overflows the §7.9.3 clamp range.
    #[test]
    fn get_mv_projection_clamps_into_mv_in_use_bits() {
        // Source 30000 * 8 / 1 = 240000 ⇒ clamps to (1<<14)-1 = 16383.
        let mv = get_mv_projection([30000, -30000], 8, 1);
        assert_eq!(mv, [16383, -16383]);
    }

    /// r205 §7.9.4 `get_block_position` valid: a tiny projection
    /// keeps the position inside both the §7.9.4 grid bound
    /// (`max8 = mi_rows/cols >> 1`) and the per-direction
    /// `MAX_OFFSET_*` window.
    #[test]
    fn get_block_position_valid_for_small_delta() {
        // mi_rows = mi_cols = 16 ⇒ max_y = max_x = 8.
        // y8 = x8 = 4. delta = 0 ⇒ project returns (4, 4).
        let pos = get_block_position(4, 4, /* dst_sign = */ 1, [0, 0], 16, 16);
        assert_eq!(pos, Some((4, 4)));
    }

    /// r205 §7.9.4 `get_block_position` invalid: a projection that
    /// would move the position outside the §7.9.4 grid bound
    /// returns `None` (= `posValid == 0`).
    #[test]
    fn get_block_position_invalid_when_outside_grid() {
        // y8 = 7 (the bottom row). A large positive projMv[0] pushes
        // the projected position past `max_y = 8`. delta = 1 << 14
        // (=16384) ⇒ offset8 = 16384 >> 6 = 256, well past the row
        // bound. Returns None.
        let pos = get_block_position(4, 7, /* dst_sign = */ 1, [16384, 0], 16, 16);
        assert_eq!(pos, None);
    }

    /// r205 §7.10.2.6 temporal-sample with a valid centre-cell MV
    /// appends a candidate to the stack. Single-pred, BLOCK_4X4 at
    /// (mi_row=2, mi_col=2): the §7.10.2.6 read site is
    /// `((mi_row + 0) | 1) >> 1, ((mi_col + 0) | 1) >> 1` = `(1, 1)`.
    /// Stamping `MotionFieldMvs[LAST_FRAME][1][1] = [40, -32]` makes
    /// the temporal sample land a candidate with weight 2.
    #[test]
    fn temporal_scan_single_pred_centre_cell_lands_candidate() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 8,
            mi_col_start: 0,
            mi_col_end: 8,
        };
        let walker = PartitionWalker::new(8, 8, geom).unwrap();
        let (gm_type, gm_params) = identity_gm();
        // mi_rows = mi_cols = 8 ⇒ h8 = w8 = 4. Stamp at (y8=1, x8=1).
        let mut mfmvs = MotionFieldMvs::new_invalid(walker.mi_rows(), walker.mi_cols());
        mfmvs.set(/* LAST_FRAME = */ 1, 1, 1, [40, -32]);
        let res = walker
            .find_mv_stack(
                2,
                2,
                BLOCK_4X4,
                [1, -1],
                false,
                /* use_ref_frame_mvs = */ true,
                gm_type,
                gm_params,
                zero_sign_bias(),
                /* allow_high_precision_mv = */ false,
                /* force_integer_mv = */ false,
                &mfmvs,
            )
            .expect("§7.10.2 driver with valid temporal candidate runs to completion");
        assert!(
            res.num_mv_found >= 1,
            "temporal scan should land at least one candidate from the populated grid cell"
        );
        // §7.10.2.6 single-pred writes to slot [0][0..2]. Per
        // §7.10.2.10 with `allow_high_precision_mv == 0` and
        // `force_integer_mv == 0`, the LSBs are stripped: 40 stays,
        // -32 stays (both are even). After §7.10.2.14 clamp the
        // values lie inside the [-MV_BORDER, +MV_BORDER + bw*8] range.
        assert_eq!(res.ref_stack_mv[0][0], [40, -32]);
    }

    /// r205 §7.10.2.6 temporal-sample compound: both reference
    /// frames' MotionFieldMvs cells must be non-sentinel or the
    /// candidate is dropped. Stamp only `LAST_FRAME` ⇒ the compound
    /// branch returns early on `RefFrame[1]`'s invalid slot, no
    /// candidate lands.
    #[test]
    fn temporal_scan_compound_drops_when_second_ref_sentinel() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 8,
            mi_col_start: 0,
            mi_col_end: 8,
        };
        let walker = PartitionWalker::new(8, 8, geom).unwrap();
        let (gm_type, gm_params) = identity_gm();
        let mut mfmvs = MotionFieldMvs::new_invalid(walker.mi_rows(), walker.mi_cols());
        // Only ref 1 stamped; ref 7 stays sentinel.
        mfmvs.set(1, 1, 1, [40, -32]);
        let res = walker
            .find_mv_stack(
                2,
                2,
                BLOCK_4X4,
                [1, 7], // compound: LAST + ALTREF
                true,
                /* use_ref_frame_mvs = */ true,
                gm_type,
                gm_params,
                zero_sign_bias(),
                false,
                false,
                &mfmvs,
            )
            .expect("§7.10.2 driver with mixed-sentinel compound grid runs to completion");
        // §7.10.2.12 extra-search compound fill still emits the two
        // global-MV slots. The temporal sample dropped its candidate
        // because slot 1's grid cell carries the sentinel.
        for idx in 0..res.num_mv_found as usize {
            // No temporal candidate (which would have been [40, -32]
            // on slot [0]); only the global-MV fill (= [0, 0] in the
            // identity-warp test fixture).
            assert_ne!(res.ref_stack_mv[idx][0], [40, -32]);
        }
    }

    /// §7.10.2 with a single stamped inter neighbour matching the
    /// block's RefFrame. The §7.10.2.2 scan_row(-1) finds the
    /// neighbour, the §7.10.2.8 search-stack appends it (NumMvFound =
    /// 1), and the §7.10.2 step 15 stamp adds REF_CAT_LEVEL bonus.
    /// After sort, the §7.10.2.12 extra-search runs (single-pred,
    /// num_mv_found = 1 < 2) but only fills global slots (not
    /// counted in NumMvFound).
    #[test]
    fn find_mv_stack_single_inter_neighbour_above_lands_in_stack() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 16,
            mi_col_start: 0,
            mi_col_end: 16,
        };
        let mut walker = PartitionWalker::new(16, 16, geom).unwrap();
        // Stamp a BLOCK_8X8 inter-block at (mi_row=2, mi_col=4) that
        // uses RefFrame[0] = LAST_FRAME = 1, with NEWMV mode and a
        // distinctive MV [32, 64].
        walker.stamp_inter_neighbour(2, 4, BLOCK_8X8, [1, -1], MODE_NEWMV, [[32, 64], [0, 0]]);
        let (gm_type, gm_params) = identity_gm();
        // Decode block at (mi_row=4, mi_col=4) BLOCK_8X8 with same
        // RefFrame[0] = 1. The scan_row(-1) walks 4x4 cells at row =
        // 4 + (-1) = 3, cols 4..=4+bw4=4+2 = 4,5. Wait — scan_row(-1)
        // reads MiSizes[3][4]; we stamped (2, 4) over 2x2 → cells
        // (2..=3, 4..=5) so (3, 4) is covered.
        let mfmvs = MotionFieldMvs::new_invalid(walker.mi_rows(), walker.mi_cols());
        let res = walker
            .find_mv_stack(
                4,
                4,
                BLOCK_8X8,
                [1, -1],
                false,
                false,
                gm_type,
                gm_params,
                zero_sign_bias(),
                true, // high-precision-on so MV passes through unchanged
                false,
                &mfmvs,
            )
            .unwrap();
        assert_eq!(res.num_mv_found, 1, "one inter neighbour ⇒ one stack slot");
        assert_eq!(res.ref_stack_mv[0][0], [32, 64]);
        assert_eq!(res.new_mv_count, 1, "NEWMV mode increments NewMvCount");
        assert_eq!(res.num_nearest, 1);
        assert_eq!(res.num_new, 1);
        // §7.10.2 step 15: REF_CAT_LEVEL bonus added for the close-match.
        // The original weight from scan_row was len * 2 = bw4*2 = 4.
        assert_eq!(res.weight_stack[0], REF_CAT_LEVEL + 4);
        // CloseMatches: 1 (foundAboveMatch = 1, foundLeftMatch = 0).
        assert_eq!(res.close_matches, 1);
        // TotalMatches: 1 (same as close — outer rings find nothing).
        assert_eq!(res.total_matches, 1);
        // §7.10.2.14: CloseMatches=1 ⇒ NewMvContext = 3 - min(numNew, 1)
        // = 3 - 1 = 2; RefMvContext = 2 + TotalMatches = 3.
        assert_eq!(res.new_mv_context, 2);
        assert_eq!(res.ref_mv_context, 3);
    }

    /// §7.10.2 with an inter neighbour to the LEFT. The §7.10.2.3
    /// scan_col(-1) finds it; foundLeftMatch = 1.
    #[test]
    fn find_mv_stack_single_inter_neighbour_left() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 16,
            mi_col_start: 0,
            mi_col_end: 16,
        };
        let mut walker = PartitionWalker::new(16, 16, geom).unwrap();
        walker.stamp_inter_neighbour(
            4,
            2,
            BLOCK_8X8,
            [1, -1],
            MODE_NEARESTMV, // not NEWMV ⇒ new_mv_count stays 0
            [[16, -32], [0, 0]],
        );
        let (gm_type, gm_params) = identity_gm();
        let mfmvs = MotionFieldMvs::new_invalid(walker.mi_rows(), walker.mi_cols());
        let res = walker
            .find_mv_stack(
                4,
                4,
                BLOCK_8X8,
                [1, -1],
                false,
                false,
                gm_type,
                gm_params,
                zero_sign_bias(),
                true,
                false,
                &mfmvs,
            )
            .unwrap();
        assert_eq!(res.num_mv_found, 1);
        assert_eq!(res.ref_stack_mv[0][0], [16, -32]);
        assert_eq!(res.new_mv_count, 0, "NEARESTMV is not has_newmv");
        assert_eq!(res.close_matches, 1);
        // §7.10.2.14: CloseMatches=1, numNew=0 ⇒ NewMvContext = 3 - 0 = 3.
        assert_eq!(res.new_mv_context, 3);
        assert_eq!(res.ref_mv_context, 3);
    }

    /// §7.10.2 with TWO inter neighbours (one above + one left). Both
    /// found ⇒ CloseMatches = 2, NewMvContext / RefMvContext from the
    /// CloseMatches >= 2 arm.
    #[test]
    fn find_mv_stack_above_and_left_neighbours() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 16,
            mi_col_start: 0,
            mi_col_end: 16,
        };
        let mut walker = PartitionWalker::new(16, 16, geom).unwrap();
        walker.stamp_inter_neighbour(2, 4, BLOCK_8X8, [1, -1], MODE_NEARESTMV, [[10, 0], [0, 0]]);
        walker.stamp_inter_neighbour(4, 2, BLOCK_8X8, [1, -1], MODE_NEWMV, [[20, 0], [0, 0]]);
        let (gm_type, gm_params) = identity_gm();
        let mfmvs = MotionFieldMvs::new_invalid(walker.mi_rows(), walker.mi_cols());
        let res = walker
            .find_mv_stack(
                4,
                4,
                BLOCK_8X8,
                [1, -1],
                false,
                false,
                gm_type,
                gm_params,
                zero_sign_bias(),
                true,
                false,
                &mfmvs,
            )
            .unwrap();
        assert_eq!(res.num_mv_found, 2);
        assert_eq!(res.close_matches, 2);
        assert_eq!(res.total_matches, 2);
        // After sort: both weights = REF_CAT_LEVEL + 4; identical, so
        // order is preserved (stable). Above was found first (scan_row
        // before scan_col), so it's index 0.
        assert_eq!(res.ref_stack_mv[0][0], [10, 0]);
        assert_eq!(res.ref_stack_mv[1][0], [20, 0]);
        // numNew = 1 (only the left neighbour was NEWMV).
        assert_eq!(res.num_new, 1);
        // §7.10.2.14: CloseMatches >= 2 ⇒ NewMvContext = 5 - min(numNew, 1)
        // = 5 - 1 = 4; RefMvContext = 5.
        assert_eq!(res.new_mv_context, 4);
        assert_eq!(res.ref_mv_context, 5);
    }

    /// §7.10.2 with an inter neighbour whose RefFrame does NOT match
    /// the block's RefFrame: the §7.10.2.7 candidate gate excludes it
    /// from the primary spatial scan (CloseMatches stays 0, numNearest
    /// stays 0). The §7.10.2.12 extra-search single-pred branch
    /// (§7.10.2.13) still picks it up as a fallback MV candidate
    /// because all `candRef > INTRA_FRAME` neighbours qualify.
    #[test]
    fn find_mv_stack_mismatched_ref_excluded_from_close_matches_picked_up_by_extra_search() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 16,
            mi_col_start: 0,
            mi_col_end: 16,
        };
        let mut walker = PartitionWalker::new(16, 16, geom).unwrap();
        // Neighbour uses GOLDEN_FRAME (= 4); block wants LAST_FRAME
        // (= 1).
        walker.stamp_inter_neighbour(2, 4, BLOCK_8X8, [4, -1], MODE_NEWMV, [[42, 42], [0, 0]]);
        let (gm_type, gm_params) = identity_gm();
        let mfmvs = MotionFieldMvs::new_invalid(walker.mi_rows(), walker.mi_cols());
        let res = walker
            .find_mv_stack(
                4,
                4,
                BLOCK_8X8,
                [1, -1],
                false,
                false,
                gm_type,
                gm_params,
                zero_sign_bias(),
                true,
                false,
                &mfmvs,
            )
            .unwrap();
        // §7.10.2 step 12-14: foundAboveMatch / foundLeftMatch only set
        // when §7.10.2.7 add_ref_mv_candidate fires search_stack —
        // which requires the cand_ref to match RefFrame[0]. Mismatched
        // ref ⇒ no close-match.
        assert_eq!(res.close_matches, 0);
        assert_eq!(res.num_nearest, 0);
        // §7.10.2.12 extra-search single-pred fallback still picks
        // the neighbour up (the §7.10.2.13 branch adds any `candRef >
        // INTRA_FRAME` MV regardless of ref match).
        assert!(
            res.num_mv_found >= 1,
            "extra-search single-pred fallback adds mismatched-ref MV"
        );
        assert_eq!(res.ref_stack_mv[0][0], [42, 42]);
    }

    /// §7.10.2 dedupe: two identical inter neighbours (same MV, same
    /// ref) ⇒ the second match increments the WeightStack rather than
    /// creating a new slot. NumMvFound stays at 1.
    #[test]
    fn find_mv_stack_dedupes_identical_mv_neighbours() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 16,
            mi_col_start: 0,
            mi_col_end: 16,
        };
        let mut walker = PartitionWalker::new(16, 16, geom).unwrap();
        // Above and left both have the same RefFrame and MV.
        walker.stamp_inter_neighbour(2, 4, BLOCK_8X8, [1, -1], MODE_NEARESTMV, [[7, 7], [0, 0]]);
        walker.stamp_inter_neighbour(4, 2, BLOCK_8X8, [1, -1], MODE_NEARESTMV, [[7, 7], [0, 0]]);
        let (gm_type, gm_params) = identity_gm();
        let mfmvs = MotionFieldMvs::new_invalid(walker.mi_rows(), walker.mi_cols());
        let res = walker
            .find_mv_stack(
                4,
                4,
                BLOCK_8X8,
                [1, -1],
                false,
                false,
                gm_type,
                gm_params,
                zero_sign_bias(),
                true,
                false,
                &mfmvs,
            )
            .unwrap();
        assert_eq!(res.num_mv_found, 1, "duplicate MV ⇒ accumulated weight");
        assert_eq!(res.ref_stack_mv[0][0], [7, 7]);
        // Both scan_row and scan_col matched ⇒ weight is 2 * (len*2) =
        // 8 before the REF_CAT_LEVEL bonus, but we only get the bonus
        // for slot 0 (numNearest = 1).
        assert_eq!(res.weight_stack[0], REF_CAT_LEVEL + 8);
        // Both Close matches still detected.
        assert_eq!(res.close_matches, 2);
    }

    /// §7.10.2.12 extra-search on single-pred with one neighbour: the
    /// global-MV tail extension does NOT increment NumMvFound for
    /// single-pred (per the §7.10.2.12 note).
    #[test]
    fn find_mv_stack_single_pred_extra_search_does_not_increment_num_mv_found() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 16,
            mi_col_start: 0,
            mi_col_end: 16,
        };
        let mut walker = PartitionWalker::new(16, 16, geom).unwrap();
        walker.stamp_inter_neighbour(2, 4, BLOCK_8X8, [1, -1], MODE_NEARESTMV, [[5, 5], [0, 0]]);
        let (gm_type, gm_params) = identity_gm();
        let mfmvs = MotionFieldMvs::new_invalid(walker.mi_rows(), walker.mi_cols());
        let res = walker
            .find_mv_stack(
                4,
                4,
                BLOCK_8X8,
                [1, -1],
                false,
                false,
                gm_type,
                gm_params,
                zero_sign_bias(),
                true,
                false,
                &mfmvs,
            )
            .unwrap();
        // One spatial candidate. NumMvFound = 1; extra-search single-
        // pred path does NOT add global-MV slots to the count.
        assert_eq!(res.num_mv_found, 1);
    }

