    // ===================== §5.11.39 `coeffs( )` =====================

    /// Test helper: build an `N`-entry CDF row (`N - 1` symbols +
    /// counter) that forces a *fresh-state* `read_symbol` to return
    /// `target_sym`. Convention: `cdf[i] = 0` for `i < target_sym` (a
    /// 0-CDF entry gives `f = 1 << 15`; the §8.2.6 `cur` for that
    /// symbol exceeds the decoder's fresh `value = (1 << 15) - 1 -
    /// paddedBuf`, keeping `value < cur` → the loop continues past
    /// `i`), then `cdf[i] = 1 << 15` for `i >= target_sym` (a `1 <<
    /// 15` entry gives `f = 0`, `cur = EC_MIN_PROB * (N - 2 - i)`,
    /// which is `<= value` → the loop breaks at the first such `i =
    /// target_sym`). The final counter entry stays at `0`.
    ///
    /// **Note**: this rig is only guaranteed on the *first* read in
    /// fresh `[0u8; _]`-init decoder state (where `value = (1 << 15) -
    /// 1 = 32767`). After one or more reads the decoder's
    /// renormalisation may push `range` above `1 << 15`, and the
    /// `cur = ((range >> 8) * (f >> EC_PROB_SHIFT)) >> (7 -
    /// EC_PROB_SHIFT)` truncation can drop below `value` even for
    /// `f = 1 << 15`. The tests using `rig_cdf` for a non-zero
    /// `target_sym` therefore arrange the relevant CDF to be the
    /// *first* read at that target — and tests that need a non-zero
    /// target after several reads use the gate-closed (`all_zero =
    /// 1`) short-circuit instead.
    fn rig_cdf<const N: usize>(target_sym: usize) -> [u16; N] {
        let mut out = [0u16; N];
        let last = N - 1;
        for (i, slot) in out.iter_mut().enumerate().take(last) {
            *slot = if i < target_sym { 0 } else { 1 << 15 };
        }
        // counter (slot N-1) stays at 0
        out
    }

    /// §5.11.39 line-3 short-circuit: when the `all_zero` S() read returns
    /// `1`, the reader returns `CoefficientsReadout {
    /// all_zero: true, eob: 0, cul_level: 0, dc_category: 0 }` with no
    /// further S() / L(1) reads. Driven by forcing the `txb_skip` CDF to
    /// always select symbol 1.
    #[test]
    fn coefficients_all_zero_short_circuits() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 8,
            mi_col_start: 0,
            mi_col_end: 8,
        };
        let mut walker = PartitionWalker::new(8, 8, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        // Force every txb_skip ctx row to select symbol 1 (all_zero = 1).
        for sz in 0..TX_SIZES {
            for ctx in 0..TXB_SKIP_CONTEXTS {
                cdfs.txb_skip[sz][ctx] = rig_cdf::<3>(1);
            }
        }
        let bytes = [0u8; 4];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 4, true).unwrap();
        // TX_4X4: 16 coefficients, scan is the identity 0..16 for tests.
        let scan: Vec<u16> = (0..16u16).collect();
        let mut quant = vec![999i32; 16]; // pre-fill to verify zero-fill
        let r = walker
            .coefficients(
                &mut dec,
                &mut cdfs,
                /* plane = */ 0,
                /* is_inter = */ 0,
                TX_4X4,
                TX_CLASS_2D,
                /* txb_skip_ctx = */ 0,
                /* dc_sign_ctx = */ 0,
                &scan,
                &mut quant,
            )
            .unwrap();
        assert!(r.all_zero);
        assert_eq!(r.eob, 0);
        assert_eq!(r.cul_level, 0);
        assert_eq!(r.dc_category, 0);
        // The §5.11.39 line 8-9 pre-loop zero-fills Quant[ 0..segEob ];
        // segEob = 16 here, so every cell is zeroed.
        assert!(quant.iter().all(|&q| q == 0));
    }

    /// §5.11.39 gate-open smoke test: `all_zero` forced to 0 (cascade
    /// fires); the reader runs to completion, producing a non-`all_zero`
    /// readout with `eob` in `1..=segEob = 1..=16`. With `[0u8;
    /// 8]`-init the §8.2.6 first-symbol selection is sym-0 for every
    /// rigged CDF whose `cdf[0] = 1 << 15`. We confirm:
    ///   * `all_zero == false` (the gate-closed test confirms the
    ///     positive case).
    ///   * `eob >= 1` (every gate-open path produces at least one
    ///     coefficient).
    ///   * `cul_level <= 63` (the §5.11.39 line-102 clamp).
    ///   * `dc_category ∈ {0, 1, 2}` (the §5.11.39 line-94
    ///     three-arm dispatch).
    #[test]
    fn coefficients_gate_open_smoke_default_cdfs() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 8,
            mi_col_start: 0,
            mi_col_end: 8,
        };
        let mut walker = PartitionWalker::new(8, 8, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        // Force txb_skip to symbol 0 (first read; sym-0 wins from value=32767).
        for sz in 0..TX_SIZES {
            for ctx in 0..TXB_SKIP_CONTEXTS {
                cdfs.txb_skip[sz][ctx] = rig_cdf::<3>(0);
            }
        }
        // The remaining CDFs stay at the §9.4 defaults; the §8.2.6
        // decoder selects whatever the default skew lands on. The test
        // only asserts structural invariants of the readout.
        let bytes = [0u8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        let scan: Vec<u16> = (0..16u16).collect();
        let mut quant = vec![0i32; 16];
        let r = walker
            .coefficients(
                &mut dec,
                &mut cdfs,
                /* plane = */ 0,
                /* is_inter = */ 0,
                TX_4X4,
                TX_CLASS_2D,
                /* txb_skip_ctx = */ 0,
                /* dc_sign_ctx = */ 0,
                &scan,
                &mut quant,
            )
            .unwrap();
        assert!(!r.all_zero, "txb_skip rigged to 0 ⇒ cascade fires");
        assert!(
            r.eob >= 1 && r.eob <= 16,
            "eob ∈ 1..=segEob = 1..=16 for TX_4X4; got {}",
            r.eob
        );
        assert!(
            r.cul_level <= 63,
            "§5.11.39 line-102 clamp ensures cul_level ≤ 63; got {}",
            r.cul_level
        );
        assert!(
            r.dc_category <= 2,
            "§5.11.39 line-94 three-arm dispatch yields {{0, 1, 2}}; got {}",
            r.dc_category
        );
        // Decoder advanced past at least the txb_skip + eob_pt_16 reads.
        assert!(
            dec.position() > 0,
            "gate-open cascade consumed at least one symbol bit"
        );
    }

    /// §5.11.39 cdf adaptation smoke test: with `all_zero` forced to 0
    /// (a §8.3 adapting CDF), the `txb_skip` row at the consulted
    /// `(txSzCtx, ctx)` cell must have its counter slot incremented
    /// (the §8.3 update increments `cdf[N]` after every successful
    /// decode). This proves the reader is actually invoking
    /// `read_symbol` against the right CDF row.
    #[test]
    fn coefficients_gate_open_adapts_txb_skip_cdf() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 8,
            mi_col_start: 0,
            mi_col_end: 8,
        };
        let mut walker = PartitionWalker::new(8, 8, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        // Force txb_skip to symbol 0 across all rows.
        for sz in 0..TX_SIZES {
            for ctx in 0..TXB_SKIP_CONTEXTS {
                cdfs.txb_skip[sz][ctx] = rig_cdf::<3>(0);
            }
        }
        // Snapshot the row that will be consulted (TX_4X4 has txSzCtx=0,
        // and the test passes txb_skip_ctx=0).
        let counter_before = cdfs.txb_skip[0][0][2];
        let bytes = [0u8; 8];
        // Critical: use disable_cdf_update = FALSE so the adaptation runs.
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, false).unwrap();
        let scan: Vec<u16> = (0..16u16).collect();
        let mut quant = vec![0i32; 16];
        let _ = walker
            .coefficients(
                &mut dec,
                &mut cdfs,
                0,
                0,
                TX_4X4,
                TX_CLASS_2D,
                0,
                0,
                &scan,
                &mut quant,
            )
            .unwrap();
        let counter_after = cdfs.txb_skip[0][0][2];
        assert!(
            counter_after > counter_before,
            "§8.3 CDF update increments the txb_skip counter slot after read"
        );
    }

    /// §5.11.39 caller-bug guards: each out-of-range argument returns
    /// [`crate::Error::PartitionWalkOutOfRange`] without touching the
    /// decoder state.
    #[test]
    fn coefficients_rejects_out_of_range_arguments() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 8,
            mi_col_start: 0,
            mi_col_end: 8,
        };
        let mut walker = PartitionWalker::new(8, 8, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let bytes = [0u8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        let scan: Vec<u16> = (0..16u16).collect();
        let mut quant = vec![0i32; 16];

        // tx_size out of range.
        let r = walker.coefficients(
            &mut dec,
            &mut cdfs,
            0,
            0,
            TX_SIZES_ALL,
            TX_CLASS_2D,
            0,
            0,
            &scan,
            &mut quant,
        );
        assert!(matches!(r, Err(crate::Error::PartitionWalkOutOfRange)));

        // tx_class out of range (TX_CLASS_VERT = 2; 3 is illegal).
        let r = walker.coefficients(
            &mut dec, &mut cdfs, 0, 0, TX_4X4, 3, 0, 0, &scan, &mut quant,
        );
        assert!(matches!(r, Err(crate::Error::PartitionWalkOutOfRange)));

        // plane out of range (> 2).
        let r = walker.coefficients(
            &mut dec,
            &mut cdfs,
            3,
            0,
            TX_4X4,
            TX_CLASS_2D,
            0,
            0,
            &scan,
            &mut quant,
        );
        assert!(matches!(r, Err(crate::Error::PartitionWalkOutOfRange)));

        // is_inter out of range (> 1).
        let r = walker.coefficients(
            &mut dec,
            &mut cdfs,
            0,
            2,
            TX_4X4,
            TX_CLASS_2D,
            0,
            0,
            &scan,
            &mut quant,
        );
        assert!(matches!(r, Err(crate::Error::PartitionWalkOutOfRange)));

        // txb_skip_ctx out of range.
        let r = walker.coefficients(
            &mut dec,
            &mut cdfs,
            0,
            0,
            TX_4X4,
            TX_CLASS_2D,
            TXB_SKIP_CONTEXTS,
            0,
            &scan,
            &mut quant,
        );
        assert!(matches!(r, Err(crate::Error::PartitionWalkOutOfRange)));

        // dc_sign_ctx out of range.
        let r = walker.coefficients(
            &mut dec,
            &mut cdfs,
            0,
            0,
            TX_4X4,
            TX_CLASS_2D,
            0,
            DC_SIGN_CONTEXTS,
            &scan,
            &mut quant,
        );
        assert!(matches!(r, Err(crate::Error::PartitionWalkOutOfRange)));

        // scan too short.
        let short_scan: Vec<u16> = (0..4u16).collect();
        let r = walker.coefficients(
            &mut dec,
            &mut cdfs,
            0,
            0,
            TX_4X4,
            TX_CLASS_2D,
            0,
            0,
            &short_scan,
            &mut quant,
        );
        assert!(matches!(r, Err(crate::Error::PartitionWalkOutOfRange)));

        // quant too small.
        let mut tiny_quant = vec![0i32; 4];
        let r = walker.coefficients(
            &mut dec,
            &mut cdfs,
            0,
            0,
            TX_4X4,
            TX_CLASS_2D,
            0,
            0,
            &scan,
            &mut tiny_quant,
        );
        assert!(matches!(r, Err(crate::Error::PartitionWalkOutOfRange)));
    }

    /// §5.11.39 line-4 `txSzCtx` derivation invariants: for every
    /// square `TX_NxN` (TX_4X4..TX_64X64) both `Tx_Size_Sqr` and
    /// `Tx_Size_Sqr_Up` return the same ordinal `n`, so the shift
    /// `(n + n + 1) >> 1` collapses to `n`. This test runs the reader
    /// across all five square ordinals with the gate-closed (`all_zero
    /// = 1`) short-circuit to confirm none trip a bounds check —
    /// proving the reader's internal `txSzCtx` formula stays in
    /// `0..TX_SIZES` across every square tx size.
    #[test]
    fn coefficients_txszctx_square_tx_sizes_do_not_panic() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 64,
            mi_col_start: 0,
            mi_col_end: 64,
        };
        let mut walker = PartitionWalker::new(64, 64, geom).unwrap();
        for tx in &[TX_4X4, TX_8X8, TX_16X16, TX_32X32, TX_64X64] {
            let mut cdfs = TileCdfContext::new_from_defaults();
            // Force txb_skip to symbol 1 (gate closed — quickest path).
            for sz in 0..TX_SIZES {
                for ctx in 0..TXB_SKIP_CONTEXTS {
                    cdfs.txb_skip[sz][ctx] = rig_cdf::<3>(1);
                }
            }
            let bytes = [0u8; 8];
            let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
            // Scan + quant sized for the largest case (TX_64X64 = 4096).
            let scan: Vec<u16> = (0..4096u16).collect();
            let mut quant = vec![0i32; 4096];
            let r = walker
                .coefficients(
                    &mut dec,
                    &mut cdfs,
                    0,
                    0,
                    *tx,
                    TX_CLASS_2D,
                    0,
                    0,
                    &scan,
                    &mut quant,
                )
                .unwrap();
            assert!(
                r.all_zero,
                "rigged all_zero=1 ⇒ short-circuit for tx={}",
                tx
            );
            assert_eq!(r.eob, 0);
        }
    }

    /// §5.11.39 line-6 `segEob` derivation cross-check: for `TX_16X64`
    /// the spec hard-codes `segEob = 512`, not the
    /// `min(1024, tx_w * tx_h) = min(1024, 1024) = 1024` it would
    /// otherwise be. The reader's `scan.len() >= segEob` guard fires
    /// when the caller passes a scan shorter than 512 — the test
    /// passes 511 cells and confirms the bug guard fires.
    #[test]
    fn coefficients_tx_16x64_uses_512_seg_eob() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 32,
            mi_col_start: 0,
            mi_col_end: 32,
        };
        let mut walker = PartitionWalker::new(32, 32, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let bytes = [0u8; 8];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 8, true).unwrap();
        // scan length 511 — just below the 512-cap.
        let scan: Vec<u16> = (0..511u16).collect();
        let mut quant = vec![0i32; 16 * 64]; // 1024 cells, fits indexing.
        let r = walker.coefficients(
            &mut dec,
            &mut cdfs,
            0,
            0,
            TX_16X64,
            TX_CLASS_2D,
            0,
            0,
            &scan,
            &mut quant,
        );
        assert!(
            matches!(r, Err(crate::Error::PartitionWalkOutOfRange)),
            "segEob = 512 for TX_16X64; scan.len() = 511 ⇒ guard fires"
        );
        // A 512-cell scan passes the guard.
        let scan_ok: Vec<u16> = (0..512u16).collect();
        let mut quant_ok = vec![0i32; 16 * 64];
        // Force all_zero to short-circuit so we don't depend on EOB tables.
        for sz in 0..TX_SIZES {
            for ctx in 0..TXB_SKIP_CONTEXTS {
                cdfs.txb_skip[sz][ctx] = rig_cdf::<3>(1);
            }
        }
        let bytes2 = [0u8; 8];
        let mut dec2 = SymbolDecoder::init_symbol(&bytes2, 8, true).unwrap();
        let r2 = walker
            .coefficients(
                &mut dec2,
                &mut cdfs,
                0,
                0,
                TX_16X64,
                TX_CLASS_2D,
                0,
                0,
                &scan_ok,
                &mut quant_ok,
            )
            .unwrap();
        assert!(r2.all_zero);
        assert_eq!(r2.eob, 0);
    }

    // ============================================================
    // r181 — §5.11.34 `residual()` outer-dispatch tests.
    // ============================================================

    /// `get_tx_size( plane=0, ... )` is a pass-through — the §5.11.37
    /// spec body line 2 short-circuits luma to the input `txSz`.
    #[test]
    fn get_tx_size_plane0_is_pass_through() {
        for tx in 0..TX_SIZES_ALL {
            assert_eq!(
                get_tx_size(0, tx, BLOCK_16X16, 0, 0),
                Some(tx),
                "plane 0 pass-through (tx_size = {tx})",
            );
        }
    }

    /// `get_tx_size` chroma path with no subsampling (4:4:4) — chroma
    /// residual equals luma residual, then §5.11.37 lookup via
    /// `Max_Tx_Size_Rect`.
    #[test]
    fn get_tx_size_chroma_no_subsampling_matches_max_tx_size_rect() {
        // BLOCK_16X16, 4:4:4 — chroma plane_sz = BLOCK_16X16; uvTx =
        // MAX_TX_SIZE_RECT[BLOCK_16X16] = TX_16X16. Neither width nor
        // height is 64, so returns uvTx = TX_16X16.
        assert_eq!(get_tx_size(1, TX_16X16, BLOCK_16X16, 0, 0), Some(TX_16X16));
        assert_eq!(get_tx_size(2, TX_16X16, BLOCK_16X16, 0, 0), Some(TX_16X16));
        // BLOCK_32X32, 4:4:4 — uvTx = MAX_TX_SIZE_RECT[BLOCK_32X32] = TX_32X32.
        assert_eq!(get_tx_size(1, TX_8X8, BLOCK_32X32, 0, 0), Some(TX_32X32));
    }

    /// `get_tx_size` 4:2:0 chroma path — BLOCK_64X64 → 32×32 chroma
    /// residual → uvTx = TX_32X32 (no 64-side clamp fires).
    #[test]
    fn get_tx_size_chroma_420_block_64x64_is_tx_32x32() {
        assert_eq!(get_tx_size(1, TX_64X64, BLOCK_64X64, 1, 1), Some(TX_32X32));
        assert_eq!(get_tx_size(2, TX_64X64, BLOCK_64X64, 1, 1), Some(TX_32X32));
    }

    /// `get_tx_size` 4:2:0 chroma path on BLOCK_128X128 — chroma
    /// plane_sz = BLOCK_64X64, uvTx = MAX_TX_SIZE_RECT[BLOCK_64X64] =
    /// TX_64X64 → triggers the §5.11.37 64-side clamp arm → TX_32X32.
    #[test]
    fn get_tx_size_chroma_128x128_420_clamps_to_32x32() {
        // 4:2:0 BLOCK_128X128 chroma plane_sz = BLOCK_64X64.
        // uvTx = MAX_TX_SIZE_RECT[BLOCK_64X64] = TX_64X64 (w = h = 64).
        // 64-clamp arm: w == 64 && h == 64, neither is 16 ⇒ TX_32X32.
        let mi_size = BLOCK_64X64 + 3; // BLOCK_128X128
        assert_eq!(get_tx_size(1, TX_64X64, mi_size, 1, 1), Some(TX_32X32));
    }

    /// `get_tx_size` out-of-range guards.
    #[test]
    fn get_tx_size_caller_bug_guards() {
        assert_eq!(get_tx_size(3, TX_4X4, BLOCK_4X4, 0, 0), None);
        assert_eq!(get_tx_size(0, TX_SIZES_ALL, BLOCK_4X4, 0, 0), None);
        assert_eq!(get_tx_size(0, TX_4X4, BLOCK_SIZES, 0, 0), None);
        assert_eq!(get_tx_size(0, TX_4X4, BLOCK_4X4, 2, 0), None);
        assert_eq!(get_tx_size(0, TX_4X4, BLOCK_4X4, 0, 2), None);
    }

    /// `residual()` gate-closed skip arm: `skip == true` short-
    /// circuits the per-TU `coefficients()` invocation. The
    /// dispatcher returns a [`ResidualReadout`] with the per-TU task
    /// enumeration filled in but the `coeffs` vec empty.
    #[test]
    fn residual_skip_arm_emits_tasks_only_no_coefficient_reads() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 16,
            mi_col_start: 0,
            mi_col_end: 16,
        };
        let mut walker = PartitionWalker::new(16, 16, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let bytes = [0u8; 16];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 16, true).unwrap();
        let pos_before = dec.position();
        let r = walker
            .residual(
                &mut dec,
                &mut cdfs,
                /* mi_row = */ 0,
                /* mi_col = */ 0,
                /* mi_size = */ BLOCK_8X8,
                /* has_chroma = */ true,
                /* subsampling_x = */ 0,
                /* subsampling_y = */ 0,
                /* is_inter = */ false,
                /* lossless = */ false,
                /* skip = */ true,
                /* tx_size = */ TX_8X8,
                /* use_128x128_superblock = */ false,
                &ResidualContext::neutral(0, 8),
            )
            .unwrap();
        let pos_after = dec.position();
        assert_eq!(r.width_chunks, 1, "BLOCK_8X8 ⇒ widthChunks = 1");
        assert_eq!(r.height_chunks, 1, "BLOCK_8X8 ⇒ heightChunks = 1");
        assert_eq!(r.mi_size_chunk, BLOCK_8X8 as u8);
        assert_eq!(r.num_planes_visited, 3, "has_chroma ⇒ 3 planes");
        // Each plane emits exactly one TU at TX_8X8 (stepX = stepY = 2
        // and num4x4W = num4x4H = 2 ⇒ one (y, x) step).
        assert_eq!(
            r.tasks.len(),
            3,
            "one TU per plane on the BLOCK_8X8 / TX_8X8 path"
        );
        assert!(r.coeffs.is_empty(), "skip == true ⇒ no coefficient reads");
        assert!(r.skip);
        assert_eq!(pos_after, pos_before, "skip arm reads no bits");
        // Per-plane task ordering: plane 0, 1, 2.
        assert_eq!(r.tasks[0].plane, 0);
        assert_eq!(r.tasks[1].plane, 1);
        assert_eq!(r.tasks[2].plane, 2);
        // Every task on the non-inter / chroma path has
        // `from_transform_tree == false`.
        for t in &r.tasks {
            assert!(!t.from_transform_tree);
        }
    }

    /// `residual()` gate-open `!skip` arm with `all_zero == 1` forced
    /// on every TU: the dispatcher invokes `coefficients()` per TU
    /// and the §5.11.39 reader short-circuits at the `all_zero` S().
    /// `coeffs.len() == tasks.len()`; every entry has `all_zero ==
    /// true` and `eob == 0`. The dispatcher completes cleanly; on
    /// every `eob == 0` TU the r182 residuals vec carries `None`
    /// (no §7.13 inverse-transform call).
    #[test]
    fn residual_no_skip_all_zero_completes_without_reconstruct_stub() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 16,
            mi_col_start: 0,
            mi_col_end: 16,
        };
        let mut walker = PartitionWalker::new(16, 16, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        // Force §5.11.39 `all_zero` S() to return 1 for every TU.
        for sz in 0..TX_SIZES {
            for ctx in 0..TXB_SKIP_CONTEXTS {
                cdfs.txb_skip[sz][ctx] = rig_cdf::<3>(1);
            }
        }
        let bytes = [0u8; 16];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 16, true).unwrap();
        let r = walker
            .residual(
                &mut dec,
                &mut cdfs,
                0,
                0,
                BLOCK_8X8,
                /* has_chroma = */ true,
                0,
                0,
                /* is_inter = */ false,
                /* lossless = */ false,
                /* skip = */ false,
                TX_8X8,
                false,
                &ResidualContext::neutral(0, 8),
            )
            .unwrap();
        assert_eq!(r.tasks.len(), 3);
        assert_eq!(r.coeffs.len(), 3, "!skip ⇒ one coefficient readout per TU");
        for c in &r.coeffs {
            assert!(c.all_zero, "rigged CDFs force all_zero = 1");
            assert_eq!(c.eob, 0);
            assert_eq!(c.cul_level, 0);
            assert_eq!(c.dc_category, 0);
        }
        // r182: every all_zero TU records `None` on the residuals vec —
        // §7.13.3 inverse_transform_2d is gated on `eob > 0`.
        assert_eq!(
            r.residuals.len(),
            3,
            "!skip ⇒ residuals length matches tasks length"
        );
        for residual in &r.residuals {
            assert!(residual.is_none(), "all_zero TU ⇒ no Residual computed");
        }
    }

    /// `residual()` lossless path forces `txSz = TX_4X4` (the §5.11.34
    /// line 12 short-circuit). Verify per-plane task `tx_size = TX_4X4`.
    #[test]
    fn residual_lossless_forces_tx_4x4_per_plane() {
        let geom = TileGeometry {
            mi_row_start: 0,
            mi_row_end: 16,
            mi_col_start: 0,
            mi_col_end: 16,
        };
        let mut walker = PartitionWalker::new(16, 16, geom).unwrap();
        let mut cdfs = TileCdfContext::new_from_defaults();
        let bytes = [0u8; 16];
        let mut dec = SymbolDecoder::init_symbol(&bytes, 16, true).unwrap();
        let r = walker
            .residual(
                &mut dec,
                &mut cdfs,
                0,
                0,
                BLOCK_8X8,
                /* has_chroma = */ true,
                0,
                0,
                false,
                /* lossless = */ true,
                /* skip = */ true,
                TX_8X8,
                false,
                &ResidualContext::neutral(0, 8),
            )
            .unwrap();
        for t in &r.tasks {
            assert_eq!(
                t.tx_size as usize, TX_4X4,
                "Lossless ⇒ TX_4X4 (got {} for plane {})",
                t.tx_size, t.plane
            );
        }
        // BLOCK_8X8 lossless ⇒ TX_4X4 ⇒ num4x4W = num4x4H = 2, stepX
        // = stepY = 1 ⇒ 4 TUs per plane × 3 planes = 12 total.
        assert_eq!(r.tasks.len(), 12);
    }

